    fn authoritative_config_pending_match_mode(
        &self,
        build_pos: i32,
    ) -> AuthoritativeConfigPendingMatchMode {
        let block_name = self
            .building_live_state_at(build_pos)
            .and_then(|building| building.projection.block_name.clone());
        match block_name.as_deref() {
            Some(
                BLOCK_NAME_BRIDGE_CONVEYOR
                | BLOCK_NAME_PHASE_CONVEYOR
                | BLOCK_NAME_BRIDGE_CONDUIT
                | BLOCK_NAME_PHASE_CONDUIT
                | BLOCK_NAME_MASS_DRIVER
                | BLOCK_NAME_PAYLOAD_MASS_DRIVER
                | BLOCK_NAME_LARGE_PAYLOAD_MASS_DRIVER,
            ) => AuthoritativeConfigPendingMatchMode::SingleLink,
            Some(
                BLOCK_NAME_POWER_NODE
                | BLOCK_NAME_POWER_NODE_LARGE
                | BLOCK_NAME_SURGE_TOWER
                | BLOCK_NAME_BEAM_LINK,
            ) => AuthoritativeConfigPendingMatchMode::PowerNode(
                self.state
                    .configured_block_projection
                    .power_node_links_by_build_pos
                    .get(&build_pos)
                    .cloned()
                    .unwrap_or_default(),
            ),
            _ => AuthoritativeConfigPendingMatchMode::Exact,
        }
    }

    fn apply_configured_block_business(
        &mut self,
        build_pos: i32,
        config_object: &TypeIoObject,
    ) -> (ConfiguredBlockOutcome, Option<String>) {
        let Some(building) = self.building_live_state_at(build_pos) else {
            return (ConfiguredBlockOutcome::RejectedMissingBuilding, None);
        };
        let Some(block_id) = building.projection.block_id else {
            return (ConfiguredBlockOutcome::RejectedMissingBlockMetadata, None);
        };
        let block_name = building
            .projection
            .block_name
            .clone()
            .or_else(|| self.loaded_world_block_name(block_id));
        let Some(block_name) = block_name else {
            return (ConfiguredBlockOutcome::RejectedMissingBlockMetadata, None);
        };

        let outcome = match block_name.as_str() {
            BLOCK_NAME_UNIT_CARGO_UNLOAD_POINT => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_unit_cargo_unload_point_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_ITEM_SOURCE => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_item_source_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_LIQUID_SOURCE => {
                if let Some(liquid_id) = configured_liquid_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_liquid_source_liquid(build_pos, liquid_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_LANDING_PAD => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_landing_pad_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_SORTER => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_sorter_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_INVERTED_SORTER => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_inverted_sorter_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_BRIDGE_CONVEYOR
            | BLOCK_NAME_PHASE_CONVEYOR
            | BLOCK_NAME_BRIDGE_CONDUIT
            | BLOCK_NAME_PHASE_CONDUIT => {
                if let Some(link) = configured_link_build_pos(build_pos, config_object) {
                    self.state
                        .configured_block_projection
                        .apply_item_bridge_link(build_pos, link);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_SWITCH | BLOCK_NAME_WORLD_SWITCH => {
                if let Some(enabled) = configured_bool(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_switch_enabled(build_pos, enabled);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_DOOR | BLOCK_NAME_DOOR_LARGE => {
                if let Some(open) = configured_bool(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_door_open(build_pos, open);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_MESSAGE | BLOCK_NAME_REINFORCED_MESSAGE | BLOCK_NAME_WORLD_MESSAGE => {
                if let Some(text) = configured_message_text(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_message_text(build_pos, text);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_CANVAS => {
                if let Some(bytes) = configured_canvas_bytes(config_object, CANVAS_CONFIG_BYTES_LEN)
                {
                    self.state
                        .configured_block_projection
                        .apply_canvas_bytes(build_pos, bytes);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_LARGE_CANVAS => {
                if let Some(bytes) =
                    configured_canvas_bytes(config_object, LARGE_CANVAS_CONFIG_BYTES_LEN)
                {
                    self.state
                        .configured_block_projection
                        .apply_canvas_bytes(build_pos, bytes);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_CONSTRUCTOR | BLOCK_NAME_LARGE_CONSTRUCTOR => {
                if let Some(block_id) = configured_block_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_constructor_recipe_block(build_pos, block_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_ILLUMINATOR => {
                if let Some(color) = configured_int(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_light_color(build_pos, color);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_PAYLOAD_SOURCE => {
                if let Some(content) =
                    configured_content_ref(config_object, &[BLOCK_CONTENT_TYPE, UNIT_CONTENT_TYPE])
                {
                    self.state
                        .configured_block_projection
                        .apply_payload_source_content(build_pos, content);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_PAYLOAD_ROUTER | BLOCK_NAME_REINFORCED_PAYLOAD_ROUTER => {
                if let Some(content) =
                    configured_content_ref(config_object, &[BLOCK_CONTENT_TYPE, UNIT_CONTENT_TYPE])
                {
                    self.state
                        .configured_block_projection
                        .apply_payload_router_sorted_content(build_pos, content);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_UNLOADER => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_unloader_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_DIRECTIONAL_UNLOADER => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_directional_unloader_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_DUCT_UNLOADER => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_duct_unloader_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_DUCT_ROUTER => {
                if let Some(item_id) = configured_item_id(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_duct_router_item(build_pos, item_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_MASS_DRIVER => {
                if let Some(link) = configured_link_build_pos(build_pos, config_object) {
                    self.state
                        .configured_block_projection
                        .apply_mass_driver_link(build_pos, link);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_PAYLOAD_MASS_DRIVER | BLOCK_NAME_LARGE_PAYLOAD_MASS_DRIVER => {
                if let Some(link) = configured_link_build_pos(build_pos, config_object) {
                    self.state
                        .configured_block_projection
                        .apply_payload_mass_driver_link(build_pos, link);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_GROUND_FACTORY
            | BLOCK_NAME_AIR_FACTORY
            | BLOCK_NAME_NAVAL_FACTORY
            | BLOCK_NAME_TANK_FABRICATOR
            | BLOCK_NAME_SHIP_FABRICATOR
            | BLOCK_NAME_MECH_FABRICATOR => {
                if let Some(current_plan) =
                    configured_int(config_object).and_then(|value| i16::try_from(value).ok())
                {
                    self.state
                        .configured_block_projection
                        .apply_unit_factory_current_plan(build_pos, current_plan);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_POWER_NODE
            | BLOCK_NAME_POWER_NODE_LARGE
            | BLOCK_NAME_SURGE_TOWER
            | BLOCK_NAME_BEAM_LINK => {
                if let Some(operation) = configured_power_node_op(build_pos, config_object) {
                    match operation {
                        ConfiguredPowerNodeOp::Toggle(target_pos) => self
                            .state
                            .configured_block_projection
                            .apply_power_node_link_toggle(build_pos, target_pos),
                        ConfiguredPowerNodeOp::FullReplace(targets) => self
                            .state
                            .configured_block_projection
                            .apply_power_node_links_full_replace(build_pos, targets),
                    }
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            BLOCK_NAME_ADDITIVE_RECONSTRUCTOR
            | BLOCK_NAME_MULTIPLICATIVE_RECONSTRUCTOR
            | BLOCK_NAME_EXPONENTIAL_RECONSTRUCTOR
            | BLOCK_NAME_TETRATIVE_RECONSTRUCTOR
            | BLOCK_NAME_TANK_REFABRICATOR
            | BLOCK_NAME_SHIP_REFABRICATOR
            | BLOCK_NAME_MECH_REFABRICATOR
            | BLOCK_NAME_PRIME_REFABRICATOR => {
                if let Some(command_id) = configured_reconstructor_command(config_object) {
                    self.state
                        .configured_block_projection
                        .apply_reconstructor_command(build_pos, command_id);
                    ConfiguredBlockOutcome::Applied
                } else {
                    ConfiguredBlockOutcome::RejectedUnsupportedConfigType
                }
            }
            _ => ConfiguredBlockOutcome::RejectedUnsupportedBlock,
        };
        (outcome, Some(block_name))
    }

