    fn should_skip_entity_snapshot_upsert(
        &mut self,
        entity_id: i32,
        is_local_player: bool,
    ) -> bool {
        if self
            .state
            .entity_snapshot_tombstone_blocks_upsert(entity_id)
        {
            self.state.record_entity_snapshot_tombstone_skip(entity_id);
            return true;
        }
        if self
            .state
            .entity_snapshot_hidden_blocks_upsert(entity_id, is_local_player)
        {
            self.state.record_entity_snapshot_hidden_skip(entity_id);
            return true;
        }
        false
    }

    fn apply_block_snapshot_entries_from_loaded_world(&mut self, payload: &[u8]) {
        if self.loaded_world_bundle().is_none() {
            return;
        }

        match self.collect_block_snapshot_entries_from_loaded_world(payload) {
            Ok(LoadedWorldBlockSnapshotEntryCollection::Complete(entries)) => {
                self.state
                    .last_loaded_world_block_snapshot_extra_entry_count = entries.len();
                self.state
                    .last_loaded_world_block_snapshot_extra_entry_parse_error = None;
                self.state
                    .applied_loaded_world_block_snapshot_extra_entry_count = self
                    .state
                    .applied_loaded_world_block_snapshot_extra_entry_count
                    .saturating_add(entries.len() as u64);
                self.apply_block_snapshot_entries_from_loaded_world_entries(entries);
            }
            Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error }) => {
                self.apply_loaded_world_block_snapshot_head_fallback();
                self.state
                    .last_loaded_world_block_snapshot_extra_entry_count = entries.len();
                self.state
                    .failed_loaded_world_block_snapshot_extra_entry_parse_count = self
                    .state
                    .failed_loaded_world_block_snapshot_extra_entry_parse_count
                    .saturating_add(1);
                self.state
                    .last_loaded_world_block_snapshot_extra_entry_parse_error = Some(error);
            }
            Err(error) => {
                self.apply_loaded_world_block_snapshot_head_fallback();
                self.state
                    .last_loaded_world_block_snapshot_extra_entry_count = 0;
                self.state
                    .failed_loaded_world_block_snapshot_extra_entry_parse_count = self
                    .state
                    .failed_loaded_world_block_snapshot_extra_entry_parse_count
                    .saturating_add(1);
                self.state
                    .last_loaded_world_block_snapshot_extra_entry_parse_error = Some(error);
            }
        }
    }

    fn apply_loaded_world_block_snapshot_head_fallback(&mut self) {
        let Some(head) = self.state.block_snapshot_head_projection.clone() else {
            return;
        };
        let block_name = self.loaded_world_block_name(head.block_id);

        self.state
            .building_table_projection
            .apply_block_snapshot_head(
                head.build_pos,
                head.block_id,
                block_name,
                head.rotation,
                head.team_id,
                head.io_version,
                head.module_bitmask,
                head.time_scale_bits,
                head.time_scale_duration_bits,
                head.last_disabler_pos,
                head.legacy_consume_connected,
                None,
                head.health_bits,
                head.enabled,
                head.efficiency,
                head.optional_efficiency,
                head.visible_flags,
                None,
                None,
                None,
            );
        self.state
            .refresh_runtime_typed_building_from_tables(head.build_pos);
    }

    fn collect_block_snapshot_entries_from_loaded_world(
        &self,
        payload: &[u8],
    ) -> Result<LoadedWorldBlockSnapshotEntryCollection, String> {
        let loaded_world = self
            .loaded_world_state()
            .ok_or_else(|| "loaded_world_state_unavailable".to_string())?;
        let mut cursor = 0usize;
        let amount = read_i16(payload, &mut cursor)
            .ok_or_else(|| "truncated_block_snapshot_payload".to_string())?;
        if amount < 0 {
            return Err(format!("negative_block_snapshot_amount:{amount}"));
        }
        let data = read_typeio_bytes_at(payload, &mut cursor)
            .ok_or_else(|| "truncated_block_snapshot_payload".to_string())?;
        if cursor != payload.len() {
            return Err(format!(
                "block_snapshot_payload_trailing_bytes:{cursor}/{}",
                payload.len()
            ));
        }

        let entry_count = usize::try_from(amount)
            .map_err(|_| format!("negative_block_snapshot_amount:{amount}"))?;
        let mut data_cursor = 0usize;
        let mut entries = Vec::with_capacity(entry_count);

        for index in 0..entry_count {
            let build_pos = match read_i32(&data, &mut data_cursor) {
                Some(value) => value,
                None => {
                    let error =
                        format!("loaded_world_block_snapshot_entry_{index}_truncated_header");
                    if entries.is_empty() {
                        return Err(error);
                    }
                    return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
                }
            };
            let block_id = match read_i16(&data, &mut data_cursor) {
                Some(value) => value,
                None => {
                    let error =
                        format!("loaded_world_block_snapshot_entry_{index}_truncated_header");
                    if entries.is_empty() {
                        return Err(error);
                    }
                    return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
                }
            };
            let (tile_x, tile_y) = unpack_point2(build_pos);
            if usize::try_from(tile_x).is_err() {
                let error =
                    format!("loaded_world_block_snapshot_entry_{index}_invalid_tile_x:{tile_x}");
                if entries.is_empty() {
                    return Err(error);
                }
                return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
            };
            if usize::try_from(tile_y).is_err() {
                let error =
                    format!("loaded_world_block_snapshot_entry_{index}_invalid_tile_y:{tile_y}");
                if entries.is_empty() {
                    return Err(error);
                }
                return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
            };
            let candidate = resolve_loaded_world_building_sync_candidate(
                &loaded_world,
                Some(&self.state.building_table_projection),
                build_pos,
            )
            .ok_or_else(|| {
                format!("loaded_world_block_snapshot_entry_{index}_missing_center:{build_pos}")
            });
            let candidate = match candidate {
                Ok(value) => value,
                Err(error) => {
                    if entries.is_empty() {
                        return Err(error);
                    }
                    return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
                }
            };
            if candidate.block_id != block_id {
                let error = format!(
                    "loaded_world_block_snapshot_entry_{index}_block_id_mismatch:{}/{}",
                    candidate.block_id, block_id
                );
                if entries.is_empty() {
                    return Err(error);
                }
                return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
            }
            if usize::try_from(block_id).is_err() {
                let error = format!(
                    "loaded_world_block_snapshot_entry_{index}_negative_block_id:{block_id}"
                );
                if entries.is_empty() {
                    return Err(error);
                }
                return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
            }
            let parsed = parse_building_sync_bytes(
                loaded_world.content_headers(),
                Some(candidate.block_name.as_str()),
                candidate.revision,
                &data[data_cursor..],
            );
            let (building, consumed) = match parsed {
                Ok(value) => value,
                Err(error) => {
                    let error = format!("loaded_world_block_snapshot_entry_{index}_parse:{error}");
                    if entries.is_empty() {
                        return Err(error);
                    }
                    return Ok(LoadedWorldBlockSnapshotEntryCollection::Partial { entries, error });
                }
            };
            data_cursor = data_cursor.saturating_add(consumed);
            let (build_turret_rotation_bits, build_turret_plans_present, build_turret_plan_count) =
                summarize_build_turret_tail_fields(&building.parsed_tail);
            let core_runtime = summarize_core_runtime_projection(&building.parsed_tail);
            let constructor_recipe_block_id =
                summarize_constructor_recipe_block_id(&building.parsed_tail);
            let constructor_runtime = summarize_constructor_projection(&building.parsed_tail);
            let unit_factory_current_plan =
                summarize_unit_factory_current_plan(&building.parsed_tail);
            let unit_factory_runtime = summarize_unit_factory_projection(&building.parsed_tail);
            let payload_loader_runtime = summarize_payload_loader_projection(&building.parsed_tail);
            let landing_pad_config_item_id =
                summarize_landing_pad_config_item_id(&building.parsed_tail);
            let landing_pad_runtime =
                summarize_landing_pad_runtime_projection(&building.parsed_tail);
            let message_text = summarize_message_tail_text(&building.parsed_tail);
            let payload_source_content = summarize_payload_source_content(&building.parsed_tail);
            let payload_source_runtime = summarize_payload_source_projection(&building.parsed_tail);
            let payload_router_sorted_content =
                summarize_payload_router_sorted_content(&building.parsed_tail);
            let payload_router_runtime = summarize_payload_router_projection(&building.parsed_tail);
            let duct_unloader_item_id = summarize_duct_unloader_item_id(&building.parsed_tail);
            let duct_unloader_runtime =
                summarize_duct_unloader_runtime_projection(&building.parsed_tail);
            let reconstructor_command_id =
                summarize_reconstructor_command_id(&building.parsed_tail);
            let memory_values_bits = summarize_memory_values_bits(&building.parsed_tail);
            let canvas_bytes = summarize_canvas_bytes(&building.parsed_tail);
            let mass_driver_link = summarize_mass_driver_link(&building.parsed_tail);
            let mass_driver_runtime = summarize_mass_driver_projection(&building.parsed_tail);
            let payload_mass_driver_link =
                summarize_payload_mass_driver_link(&building.parsed_tail);
            let payload_mass_driver_runtime =
                summarize_payload_mass_driver_projection(&building.parsed_tail);
            let sorter_runtime = summarize_sorter_runtime_projection(&building.parsed_tail);
            let item_buffer_runtime =
                summarize_item_buffer_runtime_projection(&building.parsed_tail);
            let item_bridge_runtime =
                summarize_item_bridge_runtime_projection(&building.parsed_tail);

            let entry = BlockSnapshotExtraEntrySummary {
                build_pos,
                block_id,
                block_name: Some(candidate.block_name.clone()),
                health_bits: Some(building.base.health_bits),
                rotation: Some(building.base.rotation),
                team_id: Some(building.base.team_id),
                io_version: building.base.save_version,
                enabled: building.base.enabled,
                module_bitmask: building.base.module_bitmask,
                time_scale_bits: building.base.time_scale_bits,
                time_scale_duration_bits: building.base.time_scale_duration_bits,
                last_disabler_pos: building.base.last_disabler_pos,
                legacy_consume_connected: building.base.legacy_consume_connected,
                efficiency: building.base.efficiency,
                optional_efficiency: building.base.optional_efficiency,
                visible_flags: building.base.visible_flags,
                build_turret_rotation_bits,
                build_turret_plans_present,
                build_turret_plan_count,
                core_runtime,
                constructor_recipe_block_id,
                constructor_runtime,
                unit_factory_current_plan,
                unit_factory_runtime,
                payload_loader_runtime,
                landing_pad_config_item_id,
                landing_pad_runtime,
                message_text,
                payload_source_content,
                payload_source_runtime,
                payload_router_sorted_content,
                payload_router_runtime,
                duct_unloader_item_id,
                duct_unloader_runtime,
                directional_unloader_item_id: if candidate.block_name
                    == BLOCK_NAME_DIRECTIONAL_UNLOADER
                {
                    summarize_nullable_item_config_item_id(&building.parsed_tail)
                } else {
                    None
                },
                reconstructor_command_id,
                memory_values_bits,
                canvas_bytes,
                mass_driver_link,
                mass_driver_runtime,
                payload_mass_driver_link,
                payload_mass_driver_runtime,
                sorter_runtime,
                item_buffer_runtime,
                nullable_item_id: summarize_nullable_item_config_item_id(&building.parsed_tail),
                item_bridge_link: summarize_item_bridge_link(&building.parsed_tail),
                item_bridge_runtime,
                light_color: summarize_one_i32_tail_value(&building.parsed_tail),
                switch_enabled: summarize_one_bool_tail_value(&building.parsed_tail),
                build_item_stacks: summarize_item_module_stacks(building.base.item_module.as_ref()),
                build_liquid_stacks: summarize_liquid_module_stacks(
                    building.base.liquid_module.as_ref(),
                ),
            };
            entries.push(entry);
        }

        if data_cursor != data.len() {
            return Err(format!(
                "loaded_world_block_snapshot_extra_trailing_bytes:{data_cursor}/{}",
                data.len()
            ));
        }

        Ok(LoadedWorldBlockSnapshotEntryCollection::Complete(entries))
    }

    fn apply_block_snapshot_entries_from_loaded_world_entries(
        &mut self,
        entries: Vec<BlockSnapshotExtraEntrySummary>,
    ) {
        for entry in entries {
            let config_object = loaded_world_config_object_from_block_snapshot_entry(&entry);
            self.state
                .building_table_projection
                .apply_block_snapshot_head(
                    entry.build_pos,
                    entry.block_id,
                    entry.block_name.clone(),
                    entry.rotation,
                    entry.team_id,
                    entry.io_version,
                    entry.module_bitmask,
                    entry.time_scale_bits,
                    entry.time_scale_duration_bits,
                    entry.last_disabler_pos,
                    entry.legacy_consume_connected,
                    config_object,
                    entry.health_bits,
                    entry.enabled,
                    entry.efficiency,
                    entry.optional_efficiency,
                    entry.visible_flags,
                    entry.build_turret_rotation_bits,
                    entry.build_turret_plans_present,
                    entry.build_turret_plan_count,
                );
            self.apply_loaded_world_block_snapshot_entry_business(&entry);
        }
    }

    fn apply_loaded_world_parsed_tail_business(
        &mut self,
        build_pos: i32,
        block_name: Option<&str>,
        parsed_tail: &mdt_world::ParsedBuildingTail,
    ) {
        if let Some(projection) = summarize_core_runtime_projection(parsed_tail) {
            if block_name.is_some_and(|name| name.starts_with("core-")) {
                self.state
                    .configured_block_projection
                    .apply_core_runtime(build_pos, projection);
            }
        }
        if let Some(block_id) = summarize_constructor_recipe_block_id(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_constructor_recipe_block(build_pos, block_id);
        }
        if let Some(projection) = summarize_constructor_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_constructor_runtime(build_pos, projection);
        }
        if let Some(current_plan) = summarize_unit_factory_current_plan(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_unit_factory_current_plan(build_pos, current_plan);
        }
        if let Some(projection) = summarize_unit_factory_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_unit_factory_runtime(build_pos, projection);
        }
        if let Some(projection) = summarize_payload_loader_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_loader_runtime(build_pos, projection);
        }
        if let Some(item_id) = summarize_landing_pad_config_item_id(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_landing_pad_item(build_pos, item_id);
        }
        if let Some(projection) = summarize_landing_pad_runtime_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_landing_pad_runtime(build_pos, projection);
        }
        if let Some(text) = summarize_message_tail_text(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_message_text(build_pos, text);
        }
        if let Some(content) = summarize_payload_source_content(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_source_content(build_pos, content);
        }
        if let Some(projection) = summarize_payload_source_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_source_runtime(build_pos, projection);
        }
        if let Some(content) = summarize_payload_router_sorted_content(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_router_sorted_content(build_pos, content);
        }
        if let Some(projection) = summarize_payload_router_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_router_runtime(build_pos, projection);
        }
        if let Some(item_id) = summarize_duct_unloader_item_id(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_duct_unloader_item(build_pos, item_id);
        }
        if let Some(projection) = summarize_duct_unloader_runtime_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_duct_unloader_runtime(build_pos, projection);
        }
        if let Some(command_id) = summarize_reconstructor_command_id(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_reconstructor_command(build_pos, command_id);
        }
        if let Some(projection) = summarize_reconstructor_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_reconstructor_runtime(build_pos, projection);
        }
        if let Some(values_bits) = summarize_memory_values_bits(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_memory_values_bits(build_pos, values_bits);
        }
        if let Some(bytes) = summarize_canvas_bytes(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_canvas_bytes(build_pos, bytes);
        }
        if let Some(link) = summarize_payload_mass_driver_link(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_mass_driver_link(build_pos, Some(link));
        }
        if let Some(projection) = summarize_payload_mass_driver_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_payload_mass_driver_runtime(build_pos, projection);
        }
        if let Some(projection) = summarize_unit_assembler_projection(parsed_tail) {
            self.state
                .configured_block_projection
                .apply_unit_assembler(build_pos, projection);
        }
        if let Some(item_id) = summarize_nullable_item_config_item_id(parsed_tail) {
            match block_name {
                Some(BLOCK_NAME_UNIT_CARGO_UNLOAD_POINT) => self
                    .state
                    .configured_block_projection
                    .apply_unit_cargo_unload_point_item(build_pos, item_id),
                Some(BLOCK_NAME_ITEM_SOURCE) => self
                    .state
                    .configured_block_projection
                    .apply_item_source_item(build_pos, item_id),
                Some(BLOCK_NAME_LIQUID_SOURCE) => self
                    .state
                    .configured_block_projection
                    .apply_liquid_source_liquid(build_pos, item_id),
                Some(BLOCK_NAME_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_sorter_item(build_pos, item_id),
                Some(BLOCK_NAME_INVERTED_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_inverted_sorter_item(build_pos, item_id),
                Some(BLOCK_NAME_UNLOADER) => self
                    .state
                    .configured_block_projection
                    .apply_unloader_item(build_pos, item_id),
                Some(BLOCK_NAME_DIRECTIONAL_UNLOADER) => self
                    .state
                    .configured_block_projection
                    .apply_directional_unloader_item(build_pos, item_id),
                Some(BLOCK_NAME_DUCT_ROUTER) => self
                    .state
                    .configured_block_projection
                    .apply_duct_router_item(build_pos, item_id),
                _ => {}
            }
        }
        if let Some(projection) = summarize_sorter_runtime_projection(parsed_tail) {
            match block_name {
                Some(BLOCK_NAME_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_sorter_runtime(build_pos, projection),
                Some(BLOCK_NAME_INVERTED_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_inverted_sorter_runtime(build_pos, projection),
                _ => {}
            }
        }
        if let Some(projection) = summarize_item_buffer_runtime_projection(parsed_tail) {
            if block_name == Some("junction") {
                self.state
                    .configured_block_projection
                    .apply_item_buffer_runtime(build_pos, projection);
            }
        }
        if let Some(link) = summarize_item_bridge_link(parsed_tail) {
            if matches!(
                block_name,
                Some(
                    BLOCK_NAME_BRIDGE_CONVEYOR
                        | BLOCK_NAME_PHASE_CONVEYOR
                        | BLOCK_NAME_BRIDGE_CONDUIT
                        | BLOCK_NAME_PHASE_CONDUIT
                )
            ) {
                self.state
                    .configured_block_projection
                    .apply_item_bridge_link(build_pos, Some(link));
            }
        }
        if let Some(projection) = summarize_item_bridge_runtime_projection(parsed_tail) {
            if matches!(
                block_name,
                Some(
                    BLOCK_NAME_BRIDGE_CONVEYOR
                        | BLOCK_NAME_PHASE_CONVEYOR
                        | BLOCK_NAME_BRIDGE_CONDUIT
                        | BLOCK_NAME_PHASE_CONDUIT
                )
            ) {
                self.state
                    .configured_block_projection
                    .apply_item_bridge_runtime(build_pos, projection);
            }
        }
        if let Some(link) = summarize_mass_driver_link(parsed_tail) {
            if block_name == Some(BLOCK_NAME_MASS_DRIVER) {
                self.state
                    .configured_block_projection
                    .apply_mass_driver_link(build_pos, Some(link));
            }
        }
        if let Some(projection) = summarize_mass_driver_projection(parsed_tail) {
            if block_name == Some(BLOCK_NAME_MASS_DRIVER) {
                self.state
                    .configured_block_projection
                    .apply_mass_driver_runtime(build_pos, projection);
            }
        }
        if let Some(color) = summarize_one_i32_tail_value(parsed_tail) {
            if block_name == Some(BLOCK_NAME_ILLUMINATOR) {
                self.state
                    .configured_block_projection
                    .apply_light_color(build_pos, color);
            }
        }
        if let Some(enabled) = summarize_one_bool_tail_value(parsed_tail) {
            if matches!(
                block_name,
                Some(BLOCK_NAME_SWITCH | BLOCK_NAME_WORLD_SWITCH)
            ) {
                self.state
                    .configured_block_projection
                    .apply_switch_enabled(build_pos, Some(enabled));
            }
            if matches!(block_name, Some(BLOCK_NAME_DOOR | BLOCK_NAME_DOOR_LARGE)) {
                self.state
                    .configured_block_projection
                    .apply_door_open(build_pos, Some(enabled));
            }
        }
        self.state
            .refresh_runtime_typed_building_from_tables(build_pos);
    }

    fn apply_loaded_world_block_snapshot_entry_business(
        &mut self,
        entry: &BlockSnapshotExtraEntrySummary,
    ) {
        if let Some(projection) = entry.core_runtime.clone() {
            if entry
                .block_name
                .as_deref()
                .is_some_and(|name| name.starts_with("core-"))
            {
                self.state
                    .configured_block_projection
                    .apply_core_runtime(entry.build_pos, projection);
            }
        }
        if let Some(block_id) = entry.constructor_recipe_block_id {
            self.state
                .configured_block_projection
                .apply_constructor_recipe_block(entry.build_pos, block_id);
        }
        if let Some(projection) = entry.constructor_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_constructor_runtime(entry.build_pos, projection);
        }
        if let Some(current_plan) = entry.unit_factory_current_plan {
            self.state
                .configured_block_projection
                .apply_unit_factory_current_plan(entry.build_pos, current_plan);
        }
        if let Some(projection) = entry.unit_factory_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_unit_factory_runtime(entry.build_pos, projection);
        }
        if let Some(projection) = entry.payload_loader_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_payload_loader_runtime(entry.build_pos, projection);
        }
        if let Some(item_id) = entry.landing_pad_config_item_id {
            self.state
                .configured_block_projection
                .apply_landing_pad_item(entry.build_pos, item_id);
        }
        if let Some(projection) = entry.landing_pad_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_landing_pad_runtime(entry.build_pos, projection);
        }
        if let Some(text) = entry.message_text.clone() {
            self.state
                .configured_block_projection
                .apply_message_text(entry.build_pos, text);
        }
        if let Some(content) = entry.payload_source_content {
            self.state
                .configured_block_projection
                .apply_payload_source_content(entry.build_pos, content);
        }
        if let Some(projection) = entry.payload_source_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_payload_source_runtime(entry.build_pos, projection);
        }
        if let Some(content) = entry.payload_router_sorted_content {
            self.state
                .configured_block_projection
                .apply_payload_router_sorted_content(entry.build_pos, content);
        }
        if let Some(projection) = entry.payload_router_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_payload_router_runtime(entry.build_pos, projection);
        }
        if let Some(item_id) = entry.duct_unloader_item_id {
            self.state
                .configured_block_projection
                .apply_duct_unloader_item(entry.build_pos, item_id);
        }
        if let Some(projection) = entry.duct_unloader_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_duct_unloader_runtime(entry.build_pos, projection);
        }
        if let Some(item_id) = entry.directional_unloader_item_id {
            self.state
                .configured_block_projection
                .apply_directional_unloader_item(entry.build_pos, item_id);
        }
        if let Some(command_id) = entry.reconstructor_command_id {
            self.state
                .configured_block_projection
                .apply_reconstructor_command(entry.build_pos, command_id);
        }
        if let Some(values_bits) = entry.memory_values_bits.clone() {
            self.state
                .configured_block_projection
                .apply_memory_values_bits(entry.build_pos, values_bits);
        }
        if let Some(bytes) = entry.canvas_bytes.clone() {
            self.state
                .configured_block_projection
                .apply_canvas_bytes(entry.build_pos, bytes);
        }
        if let Some(link) = entry.payload_mass_driver_link {
            self.state
                .configured_block_projection
                .apply_payload_mass_driver_link(entry.build_pos, Some(link));
        }
        if let Some(projection) = entry.payload_mass_driver_runtime.clone() {
            self.state
                .configured_block_projection
                .apply_payload_mass_driver_runtime(entry.build_pos, projection);
        }
        if let Some(projection) = entry.item_buffer_runtime.clone() {
            if entry.block_name.as_deref() == Some("junction") {
                self.state
                    .configured_block_projection
                    .apply_item_buffer_runtime(entry.build_pos, projection);
            }
        }
        if let Some(item_id) = entry.nullable_item_id {
            match entry.block_name.as_deref() {
                Some(BLOCK_NAME_UNIT_CARGO_UNLOAD_POINT) => self
                    .state
                    .configured_block_projection
                    .apply_unit_cargo_unload_point_item(entry.build_pos, item_id),
                Some(BLOCK_NAME_ITEM_SOURCE) => self
                    .state
                    .configured_block_projection
                    .apply_item_source_item(entry.build_pos, item_id),
                Some(BLOCK_NAME_LIQUID_SOURCE) => self
                    .state
                    .configured_block_projection
                    .apply_liquid_source_liquid(entry.build_pos, item_id),
                Some(BLOCK_NAME_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_sorter_item(entry.build_pos, item_id),
                Some(BLOCK_NAME_INVERTED_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_inverted_sorter_item(entry.build_pos, item_id),
                Some(BLOCK_NAME_UNLOADER) => self
                    .state
                    .configured_block_projection
                    .apply_unloader_item(entry.build_pos, item_id),
                Some(BLOCK_NAME_DIRECTIONAL_UNLOADER) => self
                    .state
                    .configured_block_projection
                    .apply_directional_unloader_item(entry.build_pos, item_id),
                Some(BLOCK_NAME_DUCT_ROUTER) => self
                    .state
                    .configured_block_projection
                    .apply_duct_router_item(entry.build_pos, item_id),
                _ => {}
            }
        }
        if let Some(projection) = entry.sorter_runtime.clone() {
            match entry.block_name.as_deref() {
                Some(BLOCK_NAME_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_sorter_runtime(entry.build_pos, projection),
                Some(BLOCK_NAME_INVERTED_SORTER) => self
                    .state
                    .configured_block_projection
                    .apply_inverted_sorter_runtime(entry.build_pos, projection),
                _ => {}
            }
        }
        if let Some(link) = entry.item_bridge_link {
            if matches!(
                entry.block_name.as_deref(),
                Some(
                    BLOCK_NAME_BRIDGE_CONVEYOR
                        | BLOCK_NAME_PHASE_CONVEYOR
                        | BLOCK_NAME_BRIDGE_CONDUIT
                        | BLOCK_NAME_PHASE_CONDUIT
                )
            ) {
                self.state
                    .configured_block_projection
                    .apply_item_bridge_link(entry.build_pos, Some(link));
            }
        }
        if let Some(projection) = entry.item_bridge_runtime.clone() {
            if matches!(
                entry.block_name.as_deref(),
                Some(
                    BLOCK_NAME_BRIDGE_CONVEYOR
                        | BLOCK_NAME_PHASE_CONVEYOR
                        | BLOCK_NAME_BRIDGE_CONDUIT
                        | BLOCK_NAME_PHASE_CONDUIT
                )
            ) {
                self.state
                    .configured_block_projection
                    .apply_item_bridge_runtime(entry.build_pos, projection);
            }
        }
        if let Some(link) = entry.mass_driver_link {
            if entry.block_name.as_deref() == Some(BLOCK_NAME_MASS_DRIVER) {
                self.state
                    .configured_block_projection
                    .apply_mass_driver_link(entry.build_pos, Some(link));
            }
        }
        if let Some(projection) = entry.mass_driver_runtime.clone() {
            if entry.block_name.as_deref() == Some(BLOCK_NAME_MASS_DRIVER) {
                self.state
                    .configured_block_projection
                    .apply_mass_driver_runtime(entry.build_pos, projection);
            }
        }
        if let Some(color) = entry.light_color {
            if entry.block_name.as_deref() == Some(BLOCK_NAME_ILLUMINATOR) {
                self.state
                    .configured_block_projection
                    .apply_light_color(entry.build_pos, color);
            }
        }
        if let Some(enabled) = entry.switch_enabled {
            if matches!(
                entry.block_name.as_deref(),
                Some(BLOCK_NAME_SWITCH | BLOCK_NAME_WORLD_SWITCH)
            ) {
                self.state
                    .configured_block_projection
                    .apply_switch_enabled(entry.build_pos, Some(enabled));
            }
            if matches!(
                entry.block_name.as_deref(),
                Some(BLOCK_NAME_DOOR | BLOCK_NAME_DOOR_LARGE)
            ) {
                self.state
                    .configured_block_projection
                    .apply_door_open(entry.build_pos, Some(enabled));
            }
        }
        self.state
            .resource_delta_projection
            .seed_world_build_items(entry.build_pos, &entry.build_item_stacks);
        self.state
            .resource_delta_projection
            .seed_world_build_liquids(entry.build_pos, &entry.build_liquid_stacks);
        self.state
            .refresh_runtime_typed_building_from_tables(entry.build_pos);
    }

    fn try_apply_local_player_spawn_from_packet(
        &mut self,
        payload: &[u8],
    ) -> Option<(i32, f32, f32)> {
        let (tile_pos, player_id) = decode_player_spawn_payload(payload)?;
        if Some(player_id) != self.state.world_player_id {
            return None;
        }

        let (tile_x, tile_y) = unpack_point2(tile_pos);
        let x = tile_x as f32 * 8.0;
        let y = tile_y as f32 * 8.0;
        self.state.world_player_x_bits = Some(x.to_bits());
        self.state.world_player_y_bits = Some(y.to_bits());
        self.state
            .entity_table_projection
            .update_local_player_position(player_id, x.to_bits(), y.to_bits(), false);
        self.state
            .refresh_runtime_typed_entity_from_tables(player_id);
        self.snapshot_input.unit_id = None;
        self.snapshot_input.dead = false;
        self.snapshot_input.position = Some((x, y));
        self.snapshot_input.view_center = Some((x, y));
        Some((player_id, x, y))
    }

    fn try_apply_player_disconnect(&mut self, player_id: i32) -> bool {
        self.state.record_entity_snapshot_tombstone(player_id);
        self.state.entity_table_projection.remove_entity(player_id);
        self.state
            .player_semantic_projection
            .remove_entity(player_id);
        self.state.remove_runtime_typed_entity(player_id);
        if Some(player_id) != self.state.world_player_id {
            return false;
        }

        self.state.world_player_semantic_projection = None;
        self.state.world_player_unit_kind = None;
        self.state.world_player_unit_value = None;
        self.state.world_player_x_bits = None;
        self.state.world_player_y_bits = None;
        self.snapshot_input.unit_id = None;
        self.snapshot_input.dead = true;
        self.snapshot_input.position = None;
        self.snapshot_input.view_center = None;
        true
    }

    fn quiet_reset_for_reconnect(&mut self) {
        let last_timeout = self.state.last_timeout;
        let timeout_count = self.state.timeout_count;
        let connect_or_loading_timeout_count = self.state.connect_or_loading_timeout_count;
        let ready_snapshot_timeout_count = self.state.ready_snapshot_timeout_count;
        let reset_count = self.state.reset_count;
        let reconnect_reset_count = self.state.reconnect_reset_count;
        let world_reload_count = self.state.world_reload_count;
        let kick_reset_count = self.state.kick_reset_count;
        let last_world_reload = self.state.last_world_reload.clone();
        let reconnect_projection = self.state.reconnect_projection.clone();
        let received_connect_redirect_count = self.state.received_connect_redirect_count;
        let last_connect_redirect_ip = self.state.last_connect_redirect_ip.clone();
        let last_connect_redirect_port = self.state.last_connect_redirect_port;
        self.pending_packets.clear();
        self.deferred_inbound_packets.clear();
        self.replayed_loading_events.clear();
        self.pending_world_stream = None;
        self.loading_world_data = false;
        self.loaded_world_bundle = None;
        self.last_inbound_at_ms = None;
        self.last_ready_inbound_liveness_at_ms = None;
        self.last_snapshot_at_ms = None;
        self.last_keepalive_at_ms = None;
        self.last_client_snapshot_at_ms = None;
        self.last_remote_ping_at_ms = None;
        self.last_remote_ping_rtt_ms = None;
        self.kicked = false;
        self.last_kick_reason_text = None;
        self.last_kick_reason_ordinal = None;
        self.last_kick_duration_ms = None;
        self.last_kick_hint_category = None;
        self.last_kick_hint_text = None;
        self.next_client_snapshot_id = 1;
        self.timed_out = false;
        self.snapshot_input = ClientSnapshotInputState::default();
        self.state = SessionState::default();
        self.stats = NetLoopStats::default();
        self.state.last_timeout = last_timeout;
        self.state.timeout_count = timeout_count;
        self.state.connect_or_loading_timeout_count = connect_or_loading_timeout_count;
        self.state.ready_snapshot_timeout_count = ready_snapshot_timeout_count;
        self.state.reset_count = reset_count;
        self.state.reconnect_reset_count = reconnect_reset_count;
        self.state.world_reload_count = world_reload_count;
        self.state.kick_reset_count = kick_reset_count;
        self.state.last_world_reload = last_world_reload;
        self.state.reconnect_projection = reconnect_projection;
        self.state.received_connect_redirect_count = received_connect_redirect_count;
        self.state.last_connect_redirect_ip = last_connect_redirect_ip;
        self.state.last_connect_redirect_port = last_connect_redirect_port;
        if self.state.reconnect_projection.reason_kind.is_none() {
            self.state.record_reconnect_projection(
                ReconnectPhaseProjection::Attempting,
                Some(ReconnectReasonKind::ManualConnect),
                Some(MANUAL_CONNECT_REASON_TEXT.to_string()),
                None,
                Some(MANUAL_CONNECT_HINT_TEXT.to_string()),
            );
        } else {
            self.state
                .set_reconnect_phase(ReconnectPhaseProjection::Attempting);
        }
        self.record_reset(SessionResetKind::Reconnect);
    }

