fn decode_effect_payload(payload: &[u8], allow_trailing: bool) -> Option<EffectSummary> {
    let mut cursor = 0usize;
    let raw_effect_id = read_i16(payload, &mut cursor)?;
    let x = read_f32(payload, &mut cursor)?;
    let y = read_f32(payload, &mut cursor)?;
    let rotation = read_f32(payload, &mut cursor)?;
    let color_rgba = read_u32(payload, &mut cursor)?;
    let data_len = payload.len().saturating_sub(cursor);
    let data_type_tag = if data_len > 0 {
        Some(payload[cursor])
    } else {
        None
    };
    let (data_kind, data_consumed_len, data_object, parse_failed, parse_error) =
        if allow_trailing && data_len > 0 {
            match read_object_effect_prefix(&payload[cursor..]) {
                Ok((object, consumed)) if consumed == data_len => (
                    Some(effect_data_kind_label(&object)),
                    Some(consumed),
                    Some(object),
                    false,
                    None,
                ),
                Ok((object, consumed)) => (
                    Some(effect_data_kind_label(&object)),
                    Some(consumed),
                    Some(object),
                    true,
                    Some(format!(
                        "trailing bytes after effect data object: consumed {consumed} of {data_len}"
                    )),
                ),
                Err(error) => (
                    None,
                    None,
                    None,
                    true,
                    Some(format!("failed to parse effect data object: {error}")),
                ),
            }
        } else {
            (None, None, None, false, None)
        };
    if !allow_trailing && cursor != payload.len() {
        return None;
    }
    Some(EffectSummary {
        effect_id: (raw_effect_id != -1).then_some(raw_effect_id),
        x,
        y,
        rotation,
        color_rgba,
        data_len,
        data_type_tag,
        data_kind,
        data_consumed_len,
        data_object,
        parse_failed,
        parse_error,
    })
}

struct EffectBusinessProjectionResult {
    projection: Option<EffectBusinessProjection>,
    path: Option<Vec<usize>>,
}

fn derive_effect_business_projection(
    state: &SessionState,
    snapshot_input: &ClientSnapshotInputState,
    effect_id: Option<i16>,
    effect_x: f32,
    effect_y: f32,
    effect_rotation: f32,
    object: Option<&TypeIoObject>,
) -> EffectBusinessProjectionResult {
    fn resolve_local_or_entity_unit_projection(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        unit_id: i32,
    ) -> Option<EffectBusinessProjection> {
        if let Some(entity) = state.entity_table_projection.by_entity_id.get(&unit_id) {
            return Some(EffectBusinessProjection::ParentRef {
                source: EffectBusinessPositionSource::EntityUnitId,
                value: unit_id,
                x_bits: entity.x_bits,
                y_bits: entity.y_bits,
            });
        }
        if snapshot_input.unit_id == Some(unit_id) {
            let position = snapshot_input.position.or_else(|| {
                Some((
                    f32::from_bits(state.world_player_x_bits?),
                    f32::from_bits(state.world_player_y_bits?),
                ))
            })?;
            return Some(EffectBusinessProjection::ParentRef {
                source: EffectBusinessPositionSource::LocalUnitId,
                value: unit_id,
                x_bits: position.0.to_bits(),
                y_bits: position.1.to_bits(),
            });
        }
        None
    }

    fn projection_from_semantic_ref(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        semantic_ref: TypeIoSemanticRef,
    ) -> Option<EffectBusinessProjection> {
        match semantic_ref {
            TypeIoSemanticRef::Content {
                content_type,
                content_id,
            } => Some(EffectBusinessProjection::ContentRef {
                kind: EffectBusinessContentKind::Content,
                content_type,
                content_id,
            }),
            TypeIoSemanticRef::TechNode {
                content_type,
                content_id,
            } => Some(EffectBusinessProjection::ContentRef {
                kind: EffectBusinessContentKind::TechNode,
                content_type,
                content_id,
            }),
            TypeIoSemanticRef::Building { build_pos } => {
                let (x, y) = world_coords_from_tile_pos(build_pos);
                Some(EffectBusinessProjection::ParentRef {
                    source: EffectBusinessPositionSource::BuildingPos,
                    value: build_pos,
                    x_bits: x.to_bits(),
                    y_bits: y.to_bits(),
                })
            }
            TypeIoSemanticRef::Unit { unit_id } => {
                resolve_local_or_entity_unit_projection(state, snapshot_input, unit_id)
            }
        }
    }

    fn projection_from_position_hint(
        position_hint: &TypeIoEffectPositionHint,
    ) -> EffectBusinessProjection {
        match position_hint {
            TypeIoEffectPositionHint::Point2 { x, y, .. } => {
                let (world_x, world_y) = point2_world_coords(*x, *y);
                EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Point2,
                    x_bits: world_x.to_bits(),
                    y_bits: world_y.to_bits(),
                }
            }
            TypeIoEffectPositionHint::PackedPoint2ArrayFirst { packed_point2, .. } => {
                let (tile_x, tile_y) = unpack_point2(*packed_point2);
                let (world_x, world_y) = point2_world_coords(i32::from(tile_x), i32::from(tile_y));
                EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Point2,
                    x_bits: world_x.to_bits(),
                    y_bits: world_y.to_bits(),
                }
            }
            TypeIoEffectPositionHint::Vec2 { x_bits, y_bits, .. }
            | TypeIoEffectPositionHint::Vec2ArrayFirst { x_bits, y_bits, .. } => {
                EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Vec2,
                    x_bits: *x_bits,
                    y_bits: *y_bits,
                }
            }
        }
    }

    fn position_bits_from_projection(projection: &EffectBusinessProjection) -> Option<(u32, u32)> {
        match projection {
            EffectBusinessProjection::ParentRef { x_bits, y_bits, .. }
            | EffectBusinessProjection::WorldPosition { x_bits, y_bits, .. } => {
                Some((*x_bits, *y_bits))
            }
            EffectBusinessProjection::LightningPath { points } => points.last().copied(),
            EffectBusinessProjection::ContentRef { .. }
            | EffectBusinessProjection::PositionTarget { .. }
            | EffectBusinessProjection::PayloadTargetContent { .. }
            | EffectBusinessProjection::LengthRay { .. }
            | EffectBusinessProjection::FloatValue(_) => None,
        }
    }

    fn ray_endpoint(
        effect_x: f32,
        effect_y: f32,
        effect_rotation: f32,
        length: f32,
    ) -> Option<(u32, u32)> {
        if !effect_x.is_finite()
            || !effect_y.is_finite()
            || !effect_rotation.is_finite()
            || !length.is_finite()
        {
            return None;
        }
        let radians = effect_rotation.to_radians();
        Some((
            (effect_x + radians.cos() * length).to_bits(),
            (effect_y + radians.sin() * length).to_bits(),
        ))
    }

    fn projection_from_object(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        value: &TypeIoObject,
    ) -> Option<EffectBusinessProjection> {
        if let Some(semantic_ref) = value.semantic_ref() {
            if let Some(projection) =
                projection_from_semantic_ref(state, snapshot_input, semantic_ref)
            {
                return Some(projection);
            }
        }
        match value {
            TypeIoObject::Float(value) => {
                Some(EffectBusinessProjection::FloatValue(value.to_bits()))
            }
            TypeIoObject::Point2 { x, y } => {
                let (world_x, world_y) = point2_world_coords(*x, *y);
                Some(EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Point2,
                    x_bits: world_x.to_bits(),
                    y_bits: world_y.to_bits(),
                })
            }
            TypeIoObject::PackedPoint2Array(values) => values.first().map(|first| {
                let (tile_x, tile_y) = unpack_point2(*first);
                let (world_x, world_y) = point2_world_coords(i32::from(tile_x), i32::from(tile_y));
                EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Point2,
                    x_bits: world_x.to_bits(),
                    y_bits: world_y.to_bits(),
                }
            }),
            TypeIoObject::Vec2 { x, y } => Some(EffectBusinessProjection::WorldPosition {
                source: EffectBusinessPositionSource::Vec2,
                x_bits: x.to_bits(),
                y_bits: y.to_bits(),
            }),
            TypeIoObject::Vec2Array(values) => {
                values
                    .first()
                    .map(|(x, y)| EffectBusinessProjection::WorldPosition {
                        source: EffectBusinessPositionSource::Vec2,
                        x_bits: x.to_bits(),
                        y_bits: y.to_bits(),
                    })
            }
            _ => None,
        }
    }

    fn explicit_position_projection(value: &TypeIoObject) -> Option<EffectBusinessProjection> {
        match value {
            TypeIoObject::Point2 { x, y } => {
                let (world_x, world_y) = point2_world_coords(*x, *y);
                Some(EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Point2,
                    x_bits: world_x.to_bits(),
                    y_bits: world_y.to_bits(),
                })
            }
            TypeIoObject::PackedPoint2Array(values) => values.first().map(|first| {
                let (tile_x, tile_y) = unpack_point2(*first);
                let (world_x, world_y) = point2_world_coords(i32::from(tile_x), i32::from(tile_y));
                EffectBusinessProjection::WorldPosition {
                    source: EffectBusinessPositionSource::Point2,
                    x_bits: world_x.to_bits(),
                    y_bits: world_y.to_bits(),
                }
            }),
            TypeIoObject::Vec2 { x, y } => Some(EffectBusinessProjection::WorldPosition {
                source: EffectBusinessPositionSource::Vec2,
                x_bits: x.to_bits(),
                y_bits: y.to_bits(),
            }),
            TypeIoObject::Vec2Array(values) => {
                values
                    .first()
                    .map(|(x, y)| EffectBusinessProjection::WorldPosition {
                        source: EffectBusinessPositionSource::Vec2,
                        x_bits: x.to_bits(),
                        y_bits: y.to_bits(),
                    })
            }
            _ => None,
        }
    }

    fn nth_explicit_position_projection_visit(
        value: &TypeIoObject,
        depth: usize,
        max_depth: usize,
        remaining_nodes: &mut usize,
        target_index: usize,
        seen_count: &mut usize,
        path: &mut Vec<usize>,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        if depth > max_depth || *remaining_nodes == 0 {
            return None;
        }

        *remaining_nodes -= 1;
        if let Some(projection) = explicit_position_projection(value) {
            if *seen_count == target_index {
                return Some((projection, path.clone()));
            }
            *seen_count += 1;
        }

        if depth == max_depth {
            return None;
        }

        let TypeIoObject::ObjectArray(values) = value else {
            return None;
        };

        for (index, nested) in values.iter().enumerate() {
            path.push(index);
            if let Some(found) = nth_explicit_position_projection_visit(
                nested,
                depth + 1,
                max_depth,
                remaining_nodes,
                target_index,
                seen_count,
                path,
            ) {
                return Some(found);
            }
            path.pop();
            if *remaining_nodes == 0 {
                break;
            }
        }

        None
    }

    fn nth_explicit_position_projection(
        object: &TypeIoObject,
        max_depth: usize,
        max_nodes: usize,
        target_index: usize,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        let mut remaining_nodes = max_nodes;
        let mut seen_count = 0usize;
        let mut path = Vec::new();
        nth_explicit_position_projection_visit(
            object,
            0,
            max_depth,
            &mut remaining_nodes,
            target_index,
            &mut seen_count,
            &mut path,
        )
    }

    fn leg_destroy_projection(
        effect_x: f32,
        effect_y: f32,
        object: &TypeIoObject,
        max_depth: usize,
        max_nodes: usize,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        let (target_projection, path) =
            nth_explicit_position_projection(object, max_depth, max_nodes, 1)
                .or_else(|| nth_explicit_position_projection(object, max_depth, max_nodes, 0))?;
        let (target_x_bits, target_y_bits) = position_bits_from_projection(&target_projection)?;
        Some((
            EffectBusinessProjection::PositionTarget {
                source_x_bits: effect_x.to_bits(),
                source_y_bits: effect_y.to_bits(),
                target_x_bits,
                target_y_bits,
            },
            path,
        ))
    }

    fn lightning_path_projection(value: &TypeIoObject) -> Option<EffectBusinessProjection> {
        let TypeIoObject::Vec2Array(values) = value else {
            return None;
        };
        let points = values
            .iter()
            .filter_map(|(x, y)| {
                (x.is_finite() && y.is_finite()).then_some((x.to_bits(), y.to_bits()))
            })
            .collect::<Vec<_>>();
        (!points.is_empty()).then_some(EffectBusinessProjection::LightningPath { points })
    }

    fn payload_target_content_content_projection(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        value: &TypeIoObject,
    ) -> Option<EffectBusinessProjection> {
        value
            .semantic_ref()
            .and_then(|semantic_ref| match semantic_ref {
                TypeIoSemanticRef::Content { content_type, .. }
                    if [BLOCK_CONTENT_TYPE, UNIT_CONTENT_TYPE].contains(&content_type) =>
                {
                    projection_from_semantic_ref(state, snapshot_input, semantic_ref)
                }
                TypeIoSemanticRef::Content { .. }
                | TypeIoSemanticRef::TechNode { .. }
                | TypeIoSemanticRef::Building { .. }
                | TypeIoSemanticRef::Unit { .. } => None,
            })
    }

    fn payload_target_content_target_bits(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        value: &TypeIoObject,
    ) -> Option<(u32, u32)> {
        let target_projection = match value {
            TypeIoObject::Point2 { .. }
            | TypeIoObject::PackedPoint2Array(_)
            | TypeIoObject::Vec2 { .. }
            | TypeIoObject::Vec2Array(_) => projection_from_object(state, snapshot_input, value),
            _ => value
                .semantic_ref()
                .and_then(|semantic_ref| match semantic_ref {
                    TypeIoSemanticRef::Building { .. } | TypeIoSemanticRef::Unit { .. } => {
                        projection_from_semantic_ref(state, snapshot_input, semantic_ref)
                    }
                    TypeIoSemanticRef::Content { .. } | TypeIoSemanticRef::TechNode { .. } => None,
                }),
        }?;
        position_bits_from_projection(&target_projection)
    }

    fn payload_target_content_projection(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        effect_x: f32,
        effect_y: f32,
        object: &TypeIoObject,
        max_depth: usize,
        max_nodes: usize,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        let content_match = object.find_first_dfs_bounded(max_depth, max_nodes, |value| {
            payload_target_content_content_projection(state, snapshot_input, value).is_some()
        })?;
        let content_projection =
            payload_target_content_content_projection(state, snapshot_input, content_match.value)?;
        let EffectBusinessProjection::ContentRef {
            content_type,
            content_id,
            ..
        } = content_projection
        else {
            return None;
        };
        let target_match = object.find_first_dfs_bounded(max_depth, max_nodes, |value| {
            payload_target_content_target_bits(state, snapshot_input, value).is_some()
        })?;
        let (target_x_bits, target_y_bits) =
            payload_target_content_target_bits(state, snapshot_input, target_match.value)?;
        Some((
            EffectBusinessProjection::PayloadTargetContent {
                source_x_bits: effect_x.to_bits(),
                source_y_bits: effect_y.to_bits(),
                target_x_bits,
                target_y_bits,
                content_type,
                content_id,
            },
            target_match.path,
        ))
    }

    fn projection_from_contract_object(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        contract: RuntimeEffectContract,
        effect_x: f32,
        effect_y: f32,
        effect_rotation: f32,
        value: &TypeIoObject,
    ) -> Option<EffectBusinessProjection> {
        match contract {
            RuntimeEffectContract::LightningPath => lightning_path_projection(value),
            RuntimeEffectContract::PointHit => None,
            RuntimeEffectContract::DrillSteam => None,
            RuntimeEffectContract::LegDestroy => None,
            RuntimeEffectContract::ShieldBreak => None,
            RuntimeEffectContract::BlockContentIcon => {
                value
                    .semantic_ref()
                    .and_then(|semantic_ref| match semantic_ref {
                        TypeIoSemanticRef::Content {
                            content_type: BLOCK_CONTENT_TYPE,
                            ..
                        } => projection_from_semantic_ref(state, snapshot_input, semantic_ref),
                        TypeIoSemanticRef::Content { .. }
                        | TypeIoSemanticRef::TechNode { .. }
                        | TypeIoSemanticRef::Building { .. }
                        | TypeIoSemanticRef::Unit { .. } => None,
                    })
            }
            RuntimeEffectContract::ContentIcon => {
                value
                    .semantic_ref()
                    .and_then(|semantic_ref| match semantic_ref {
                        TypeIoSemanticRef::Content { content_type, .. }
                            if [BLOCK_CONTENT_TYPE, UNIT_CONTENT_TYPE].contains(&content_type) =>
                        {
                            projection_from_semantic_ref(state, snapshot_input, semantic_ref)
                        }
                        TypeIoSemanticRef::Content { .. }
                        | TypeIoSemanticRef::TechNode { .. }
                        | TypeIoSemanticRef::Building { .. }
                        | TypeIoSemanticRef::Unit { .. } => None,
                    })
            }
            RuntimeEffectContract::PositionTarget | RuntimeEffectContract::PointBeam => {
                let target_projection = match value {
                    TypeIoObject::Point2 { .. }
                    | TypeIoObject::PackedPoint2Array(_)
                    | TypeIoObject::Vec2 { .. }
                    | TypeIoObject::Vec2Array(_) => {
                        projection_from_object(state, snapshot_input, value)
                    }
                    _ => value
                        .semantic_ref()
                        .and_then(|semantic_ref| match semantic_ref {
                            TypeIoSemanticRef::Building { .. } | TypeIoSemanticRef::Unit { .. } => {
                                projection_from_semantic_ref(state, snapshot_input, semantic_ref)
                            }
                            TypeIoSemanticRef::Content { .. }
                            | TypeIoSemanticRef::TechNode { .. } => None,
                        }),
                }?;
                let (target_x_bits, target_y_bits) =
                    position_bits_from_projection(&target_projection)?;
                Some(EffectBusinessProjection::PositionTarget {
                    source_x_bits: effect_x.to_bits(),
                    source_y_bits: effect_y.to_bits(),
                    target_x_bits,
                    target_y_bits,
                })
            }
            RuntimeEffectContract::PayloadTargetContent => None,
            RuntimeEffectContract::DropItem => {
                value
                    .semantic_ref()
                    .and_then(|semantic_ref| match semantic_ref {
                        TypeIoSemanticRef::Content {
                            content_type: ITEM_CONTENT_TYPE,
                            ..
                        } => projection_from_semantic_ref(state, snapshot_input, semantic_ref),
                        TypeIoSemanticRef::Content { .. }
                        | TypeIoSemanticRef::TechNode { .. }
                        | TypeIoSemanticRef::Building { .. }
                        | TypeIoSemanticRef::Unit { .. } => None,
                    })
            }
            RuntimeEffectContract::FloatLength => match value {
                TypeIoObject::Float(length) => {
                    let (target_x_bits, target_y_bits) =
                        ray_endpoint(effect_x, effect_y, effect_rotation, *length)?;
                    Some(EffectBusinessProjection::LengthRay {
                        source_x_bits: effect_x.to_bits(),
                        source_y_bits: effect_y.to_bits(),
                        target_x_bits,
                        target_y_bits,
                        rotation_bits: effect_rotation.to_bits(),
                        length_bits: length.to_bits(),
                    })
                }
                _ => None,
            },
            RuntimeEffectContract::UnitParent => {
                value
                    .semantic_ref()
                    .and_then(|semantic_ref| match semantic_ref {
                        TypeIoSemanticRef::Unit { .. } => {
                            projection_from_semantic_ref(state, snapshot_input, semantic_ref)
                        }
                        TypeIoSemanticRef::Content { .. }
                        | TypeIoSemanticRef::TechNode { .. }
                        | TypeIoSemanticRef::Building { .. } => None,
                    })
            }
        }
    }

    fn first_resolvable_dfs_projection(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        object: &TypeIoObject,
        max_depth: usize,
        max_nodes: usize,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        object
            .find_first_dfs_bounded(max_depth, max_nodes, |value| {
                projection_from_object(state, snapshot_input, value).is_some()
            })
            .and_then(|matched| {
                projection_from_object(state, snapshot_input, matched.value)
                    .map(|projection| (projection, matched.path))
            })
    }

    fn first_contract_projection(
        state: &SessionState,
        snapshot_input: &ClientSnapshotInputState,
        contract: RuntimeEffectContract,
        effect_x: f32,
        effect_y: f32,
        effect_rotation: f32,
        object: &TypeIoObject,
        max_depth: usize,
        max_nodes: usize,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        if matches!(contract, RuntimeEffectContract::PayloadTargetContent) {
            return payload_target_content_projection(
                state,
                snapshot_input,
                effect_x,
                effect_y,
                object,
                max_depth,
                max_nodes,
            );
        }
        if matches!(contract, RuntimeEffectContract::LegDestroy) {
            return leg_destroy_projection(effect_x, effect_y, object, max_depth, max_nodes);
        }
        if let Some(projection) = projection_from_contract_object(
            state,
            snapshot_input,
            contract,
            effect_x,
            effect_y,
            effect_rotation,
            object,
        ) {
            return Some((projection, Vec::new()));
        }
        object
            .find_first_dfs_bounded(max_depth, max_nodes, |value| {
                projection_from_contract_object(
                    state,
                    snapshot_input,
                    contract,
                    effect_x,
                    effect_y,
                    effect_rotation,
                    value,
                )
                .is_some()
            })
            .and_then(|matched| {
                projection_from_contract_object(
                    state,
                    snapshot_input,
                    contract,
                    effect_x,
                    effect_y,
                    effect_rotation,
                    matched.value,
                )
                .map(|projection| (projection, matched.path))
            })
    }

    fn normalize_effect_business_path(path: Vec<usize>) -> Option<Vec<usize>> {
        (!path.is_empty()).then_some(path)
    }

    fn pick_leftmost_depth_first_candidate(
        candidates: Vec<(EffectBusinessProjection, Vec<usize>)>,
    ) -> Option<(EffectBusinessProjection, Vec<usize>)> {
        candidates
            .into_iter()
            .min_by(|(_, left_path), (_, right_path)| left_path.cmp(right_path))
    }

    const EFFECT_BUSINESS_MAX_DEPTH: usize = 3;
    const EFFECT_BUSINESS_MAX_NODES: usize = 64;

    let Some(object) = object else {
        return EffectBusinessProjectionResult {
            projection: None,
            path: None,
        };
    };
    if let Some(contract) = effect_contract(effect_id) {
        if let Some((projection, path)) = first_contract_projection(
            state,
            snapshot_input,
            contract,
            effect_x,
            effect_y,
            effect_rotation,
            object,
            EFFECT_BUSINESS_MAX_DEPTH,
            EFFECT_BUSINESS_MAX_NODES,
        ) {
            return EffectBusinessProjectionResult {
                projection: Some(projection),
                path: normalize_effect_business_path(path),
            };
        }
        if !matches!(contract, RuntimeEffectContract::LightningPath) {
            return EffectBusinessProjectionResult {
                projection: None,
                path: None,
            };
        }
    }
    let summary = object.effect_summary();
    let unresolved_parent_hint = summary.first_parent_ref.as_ref().is_some_and(|matched| {
        matches!(matched.semantic_ref, TypeIoSemanticRef::Unit { unit_id } if resolve_local_or_entity_unit_projection(state, snapshot_input, unit_id).is_none())
    });

    let mut hint_candidates = Vec::new();
    if let Some(semantic_match) = summary.first_semantic_ref.as_ref() {
        if let Some(projection) =
            projection_from_semantic_ref(state, snapshot_input, semantic_match.semantic_ref)
        {
            hint_candidates.push((projection, semantic_match.path.clone()));
        }
    }
    if let Some(position_hint) = summary.first_position_hint.as_ref() {
        hint_candidates.push((
            projection_from_position_hint(position_hint),
            position_hint.path().to_vec(),
        ));
    }
    if let Some(float_match) = object.find_first_dfs_bounded(
        EFFECT_BUSINESS_MAX_DEPTH,
        EFFECT_BUSINESS_MAX_NODES,
        |value| matches!(value, TypeIoObject::Float(_)),
    ) {
        if let TypeIoObject::Float(value) = float_match.value {
            hint_candidates.push((
                EffectBusinessProjection::FloatValue(value.to_bits()),
                float_match.path,
            ));
        }
    }

    let matched = if unresolved_parent_hint {
        first_resolvable_dfs_projection(
            state,
            snapshot_input,
            object,
            EFFECT_BUSINESS_MAX_DEPTH,
            EFFECT_BUSINESS_MAX_NODES,
        )
    } else {
        pick_leftmost_depth_first_candidate(hint_candidates).or_else(|| {
            first_resolvable_dfs_projection(
                state,
                snapshot_input,
                object,
                EFFECT_BUSINESS_MAX_DEPTH,
                EFFECT_BUSINESS_MAX_NODES,
            )
        })
    };

    match matched {
        Some((projection, path)) => EffectBusinessProjectionResult {
            projection: Some(projection),
            path: normalize_effect_business_path(path),
        },
        None => EffectBusinessProjectionResult {
            projection: None,
            path: None,
        },
    }
}

fn world_coords_from_tile_pos(tile_pos: i32) -> (f32, f32) {
    let (tile_x, tile_y) = unpack_point2(tile_pos);
    point2_world_coords(i32::from(tile_x), i32::from(tile_y))
}

fn world_coords_to_tile_pos(x_bits: u32, y_bits: u32) -> Option<i32> {
    let x = f32::from_bits(x_bits);
    let y = f32::from_bits(y_bits);
    if !x.is_finite() || !y.is_finite() {
        return None;
    }
    Some(pack_point2(
        (x / 8.0).floor() as i32,
        (y / 8.0).floor() as i32,
    ))
}

fn point2_world_coords(x: i32, y: i32) -> (f32, f32) {
    (x as f32 * 8.0, y as f32 * 8.0)
}

fn decode_debug_status_payload(payload: &[u8]) -> Option<DebugStatusSummary> {
    let mut cursor = 0usize;
    let value = read_i32(payload, &mut cursor)?;
    let last_client_snapshot = read_i32(payload, &mut cursor)?;
    let snapshots_sent = read_i32(payload, &mut cursor)?;
    (cursor == payload.len()).then_some(DebugStatusSummary {
        value,
        last_client_snapshot,
        snapshots_sent,
    })
}

fn decode_trace_info_payload(payload: &[u8]) -> Option<TraceInfoSummary> {
    let mut cursor = 0usize;
    let raw_player_id = read_i32(payload, &mut cursor)?;
    let ip = read_typeio_string_at(payload, &mut cursor)?;
    let uuid = read_typeio_string_at(payload, &mut cursor)?;
    let locale = read_typeio_string_at(payload, &mut cursor)?;
    let modded = read_u8(payload, &mut cursor)? != 0;
    let mobile = read_u8(payload, &mut cursor)? != 0;
    let times_joined = read_i32(payload, &mut cursor)?;
    let times_kicked = read_i32(payload, &mut cursor)?;
    let ips = read_typeio_string_array_at(payload, &mut cursor)?;
    let names = read_typeio_string_array_at(payload, &mut cursor)?;
    (cursor == payload.len()).then_some(TraceInfoSummary {
        player_id: (raw_player_id != -1).then_some(raw_player_id),
        ip,
        uuid,
        locale,
        modded,
        mobile,
        times_joined,
        times_kicked,
        ips,
        names,
    })
}

fn decode_remove_queue_block_payload(payload: &[u8]) -> Option<(i32, i32, bool)> {
    if payload.len() < 9 {
        return None;
    }
    let x = i32::from_be_bytes(payload[0..4].try_into().ok()?);
    let y = i32::from_be_bytes(payload[4..8].try_into().ok()?);
    let breaking = payload[8] != 0;
    Some((x, y, breaking))
}

