fn parse_player_sync_rows_from_entity_snapshot(
    payload: &[u8],
) -> Result<Vec<EntityPlayerSyncRow>, EntityPlayerSyncRowsParseError> {
    const PLAYER_ENTITY_CLASS_ID: u8 = 12;

    if payload.len() < 4 {
        return Ok(Vec::new());
    }

    let amount = u16::from_be_bytes([payload[0], payload[1]]);
    if amount == 0 {
        return Ok(Vec::new());
    }
    let max_rows = usize::from(amount);

    let Some(body_len_bytes) = payload.get(2..4) else {
        return Ok(Vec::new());
    };
    let body_len = u16::from_be_bytes(body_len_bytes.try_into().unwrap()) as usize;
    let Some(body) = payload.get(4..4 + body_len) else {
        return Ok(Vec::new());
    };
    let Some(last_start) = body.len().checked_sub(5) else {
        return Ok(Vec::new());
    };

    let mut rows = Vec::new();
    let mut last_end = 0usize;
    for start in 0..=last_start {
        if start < last_end {
            continue;
        }
        let entity_id = i32::from_be_bytes(body[start..start + 4].try_into().unwrap());
        if body[start + 4] != PLAYER_ENTITY_CLASS_ID {
            continue;
        }
        if let Ok((sync, consumed)) = parse_entity_player_sync_bytes(&body[start + 5..]) {
            let end = start.saturating_add(5).saturating_add(consumed);
            rows.push(EntityPlayerSyncRow {
                entity_id,
                sync,
                start,
                end,
            });
            if rows.len() > max_rows {
                return Err(EntityPlayerSyncRowsParseError::ParseableRowsExceedAmount {
                    rows: rows.len(),
                    amount,
                });
            }
            last_end = end;
        }
    }
    Ok(rows)
}

fn parse_alpha_sync_rows_from_entity_snapshot_prefix(
    payload: &[u8],
) -> Result<Vec<EntityAlphaSyncRow>, String> {
    if payload.len() < 4 {
        return Ok(Vec::new());
    }

    let amount = u16::from_be_bytes([payload[0], payload[1]]);
    if amount == 0 {
        return Ok(Vec::new());
    }

    let Some(body_len_bytes) = payload.get(2..4) else {
        return Ok(Vec::new());
    };
    let body_len = u16::from_be_bytes(body_len_bytes.try_into().unwrap()) as usize;
    let Some(body) = payload.get(4..4 + body_len) else {
        return Ok(Vec::new());
    };

    let mut rows = Vec::new();
    let mut cursor = 0usize;
    let max_rows = usize::from(amount);
    while cursor.saturating_add(5) <= body.len() && rows.len() < max_rows {
        let entity_id = i32::from_be_bytes(body[cursor..cursor + 4].try_into().unwrap());
        let class_id = body[cursor + 4];
        match class_id {
            12 => {
                let (_, consumed) = parse_entity_player_sync_bytes(&body[cursor + 5..])
                    .map_err(|error| format!("entity_snapshot_known_prefix_player:{error}"))?;
                cursor = cursor.saturating_add(5).saturating_add(consumed);
            }
            _ if ALPHA_SHAPE_ENTITY_CLASS_IDS.contains(&class_id) => {
                let (sync, consumed) = parse_entity_alpha_sync_bytes(&body[cursor + 5..])
                    .map_err(|error| format!("entity_snapshot_known_prefix_alpha:{error}"))?;
                let end = cursor.saturating_add(5).saturating_add(consumed);
                rows.push(EntityAlphaSyncRow {
                    entity_id,
                    class_id,
                    sync,
                    start: cursor,
                    end,
                });
                cursor = end;
            }
            _ => break,
        }
    }

    Ok(rows)
}

fn parse_building_sync_rows_from_entity_snapshot_with_loaded_world(
    payload: &[u8],
    loaded_world: Option<LoadedWorldState<'_>>,
    building_table: Option<&BuildingTableProjection>,
) -> Result<Vec<EntityBuildingSyncRow>, String> {
    let Some(loaded_world) = loaded_world.as_ref() else {
        return Ok(Vec::new());
    };
    if payload.len() < 4 {
        return Ok(Vec::new());
    }

    let amount = u16::from_be_bytes([payload[0], payload[1]]);
    if amount == 0 {
        return Ok(Vec::new());
    }

    let Some(body_len_bytes) = payload.get(2..4) else {
        return Ok(Vec::new());
    };
    let body_len = u16::from_be_bytes(body_len_bytes.try_into().unwrap()) as usize;
    let Some(body) = payload.get(4..4 + body_len) else {
        return Ok(Vec::new());
    };
    let Some(last_start) = body.len().checked_sub(5) else {
        return Ok(Vec::new());
    };

    let mut rows = Vec::new();
    let mut last_end = 0usize;
    let max_rows = usize::from(amount);
    for start in 0..=last_start {
        if start < last_end || rows.len() >= max_rows {
            continue;
        }
        let entity_id = i32::from_be_bytes(body[start..start + 4].try_into().unwrap());
        let class_id = body[start + 4];
        if !is_building_entity_class_id(class_id) {
            continue;
        }
        let Some(candidate) =
            resolve_loaded_world_building_sync_candidate(loaded_world, building_table, entity_id)
        else {
            continue;
        };
        let (sync, consumed) = parse_building_sync_bytes(
            loaded_world.content_headers(),
            Some(candidate.block_name.as_str()),
            candidate.revision,
            &body[start + 5..],
        )
        .map_err(|error| format!("entity_snapshot_building:{error}"))?;
        let end = start.saturating_add(5).saturating_add(consumed);
        rows.push(EntityBuildingSyncRow {
            entity_id,
            class_id,
            build_pos: candidate.build_pos,
            block_id: candidate.block_id,
            sync,
            x_bits: candidate.x_bits,
            y_bits: candidate.y_bits,
            start,
            end,
        });
        last_end = end;
    }

    Ok(rows)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct LoadedWorldBuildingSyncCandidate {
    build_pos: i32,
    block_id: i16,
    revision: u8,
    x_bits: u32,
    y_bits: u32,
    block_name: String,
}

fn resolve_loaded_world_building_sync_candidate(
    loaded_world: &LoadedWorldState<'_>,
    building_table: Option<&BuildingTableProjection>,
    build_pos: i32,
) -> Option<LoadedWorldBuildingSyncCandidate> {
    let (tile_x, tile_y) = unpack_point2(build_pos);
    let tile_x = usize::try_from(tile_x).ok()?;
    let tile_y = usize::try_from(tile_y).ok()?;
    let projection = building_table.and_then(|table| table.by_build_pos.get(&build_pos));
    let block_id = projection.and_then(|building| building.block_id)?;
    let block_name = projection
        .and_then(|building| building.block_name.clone())
        .or_else(|| {
            usize::try_from(block_id)
                .ok()
                .and_then(|block_content_id| {
                    loaded_world.content_name(BLOCK_CONTENT_TYPE, block_content_id)
                })
                .map(str::to_string)
        })?;
    let revision = projection.and_then(|building| building.io_version)?;
    Some(LoadedWorldBuildingSyncCandidate {
        build_pos,
        block_id,
        revision,
        x_bits: (tile_x as f32 * 8.0).to_bits(),
        y_bits: (tile_y as f32 * 8.0).to_bits(),
        block_name,
    })
}

