    fn decode_hex_text(text: &str) -> Vec<u8> {
        let cleaned = text
            .chars()
            .filter(|c| !c.is_whitespace())
            .collect::<String>();
        (0..cleaned.len())
            .step_by(2)
            .map(|i| u8::from_str_radix(&cleaned[i..i + 2], 16).unwrap())
            .collect()
    }

    fn encode_state_snapshot_payload(
        wave_time_bits: u32,
        wave: i32,
        enemies: i32,
        paused: bool,
        game_over: bool,
        time_data: i32,
        tps: u8,
        rand0: i64,
        rand1: i64,
        core_data: &[u8],
    ) -> Vec<u8> {
        let mut payload = Vec::new();
        payload.extend_from_slice(&wave_time_bits.to_be_bytes());
        payload.extend_from_slice(&wave.to_be_bytes());
        payload.extend_from_slice(&enemies.to_be_bytes());
        payload.push(u8::from(paused));
        payload.push(u8::from(game_over));
        payload.extend_from_slice(&time_data.to_be_bytes());
        payload.push(tps);
        payload.extend_from_slice(&rand0.to_be_bytes());
        payload.extend_from_slice(&rand1.to_be_bytes());
        payload.extend_from_slice(&(core_data.len() as u16).to_be_bytes());
        payload.extend_from_slice(core_data);
        payload
    }

    fn sample_connect_payload() -> Vec<u8> {
        decode_hex_text(include_str!(
            "../../../tests/src/test/resources/connect-packet.hex"
        ))
    }

    fn parse_generated_java_class_id(source: &str) -> Option<u8> {
        let marker = "public int classId() {";
        let marker_start = source.find(marker)?;
        let rest = &source[marker_start + marker.len()..];
        let return_start = rest.find("return ")?;
        let rest = &rest[return_start + "return ".len()..];
        let end = rest.find(';')?;
        rest[..end].trim().parse().ok()
    }

    fn fallback_generated_java_syncc_class_ids() -> BTreeSet<u8> {
        BTreeSet::from([
            0, 2, 3, 4, 5, 10, 12, 13, 14, 16, 17, 18, 19, 20, 21, 23, 24, 26, 29, 30, 31, 32, 33,
            35, 36, 39, 43, 45, 46,
        ])
    }

    fn generated_java_syncc_class_ids() -> BTreeSet<u8> {
        let dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("../../core/build/generated/source/kapt/main/mindustry/gen");
        let mut ids = BTreeSet::new();
        let Ok(entries) = fs::read_dir(dir) else {
            return fallback_generated_java_syncc_class_ids();
        };
        for entry in entries {
            let path = entry.unwrap().path();
            if path.extension().and_then(|value| value.to_str()) != Some("java") {
                continue;
            }
            let source = fs::read_to_string(path).unwrap();
            let Some(class_decl) = source
                .lines()
                .map(str::trim)
                .find(|line| line.starts_with("public class "))
            else {
                continue;
            };
            if !class_decl.contains("Syncc") {
                continue;
            }
            ids.insert(
                parse_generated_java_class_id(&source)
                    .unwrap_or_else(|| panic!("missing generated Java classId")),
            );
        }
        if ids.is_empty() {
            return fallback_generated_java_syncc_class_ids();
        }
        ids
    }

    fn current_rust_entity_snapshot_family_class_ids() -> BTreeSet<u8> {
        let mut ids = BTreeSet::new();
        ids.extend(ALPHA_SHAPE_ENTITY_CLASS_IDS);
        ids.extend(crate::entity_snapshot_families::BUILDING_ENTITY_CLASS_IDS);
        ids.extend(MECH_SHAPE_ENTITY_CLASS_IDS);
        ids.extend(MISSILE_SHAPE_ENTITY_CLASS_IDS);
        ids.extend(PAYLOAD_SHAPE_ENTITY_CLASS_IDS);
        ids.extend(BUILDING_TETHER_PAYLOAD_ENTITY_CLASS_IDS);
        ids.extend(FIRE_ENTITY_CLASS_IDS);
        ids.extend(PUDDLE_ENTITY_CLASS_IDS);
        ids.extend(WEATHER_STATE_ENTITY_CLASS_IDS);
        ids.extend(WORLD_LABEL_ENTITY_CLASS_IDS);
        ids.insert(crate::session_state::EntityTableProjection::LOCAL_PLAYER_CLASS_ID);
        ids
    }

    fn sample_world_stream_bytes() -> Vec<u8> {
        decode_hex_text(include_str!(
            "../../../tests/src/test/resources/world-stream.hex"
        ))
    }

    fn ingest_sample_world(session: &mut ClientSession) {
        let compressed_world_stream = sample_world_stream_bytes();
        let (begin_packet, chunk_packets) =
            encode_world_stream_packets(&compressed_world_stream, 7, 1024).unwrap();
        session.ingest_packet_bytes(&begin_packet).unwrap();
        for chunk in chunk_packets {
            session.ingest_packet_bytes(&chunk).unwrap();
        }
    }

    fn sample_build_positions_with_centers(session: &ClientSession, count: usize) -> Vec<i32> {
        let positions = session
            .loaded_world_bundle()
            .unwrap()
            .world
            .building_centers
            .iter()
            .take(count)
            .map(|center| {
                pack_point2(
                    i32::try_from(center.x).unwrap(),
                    i32::try_from(center.y).unwrap(),
                )
            })
            .collect::<Vec<_>>();
        assert_eq!(
            positions.len(),
            count,
            "sample world missing building centers"
        );
        positions
    }

    fn sample_empty_tile_positions_without_centers(
        session: &ClientSession,
        count: usize,
    ) -> Vec<i32> {
        let positions = session
            .loaded_world_bundle()
            .unwrap()
            .world
            .tiles
            .iter()
            .filter(|tile| tile.block_id == 0 && tile.building_center_index.is_none())
            .take(count)
            .map(|tile| {
                pack_point2(
                    i32::try_from(tile.x).unwrap(),
                    i32::try_from(tile.y).unwrap(),
                )
            })
            .collect::<Vec<_>>();
        assert_eq!(positions.len(), count, "sample world missing empty tiles");
        positions
    }

    fn build_pos_to_world_xy(build_pos: i32) -> (usize, usize) {
        let (x, y) = unpack_point2(build_pos);
        (
            usize::try_from(i32::from(x)).unwrap(),
            usize::try_from(i32::from(y)).unwrap(),
        )
    }

