    fn loaded_world_content_id_for_name(
        session: &ClientSession,
        content_type: u8,
        content_name: &str,
    ) -> i16 {
        let loaded = session.loaded_world_state().unwrap();
        let names = &loaded.content_entry(content_type).unwrap().names;
        let content_id = names
            .iter()
            .position(|name| name == content_name)
            .unwrap_or_else(|| {
                panic!("missing content name {content_name} for type {content_type}")
            });
        i16::try_from(content_id).unwrap()
    }

    fn loaded_world_block_id_for_name(session: &ClientSession, block_name: &str) -> i16 {
        loaded_world_content_id_for_name(session, BLOCK_CONTENT_TYPE, block_name)
    }

    fn canvas_config_bytes(len: usize, seed: u8) -> Vec<u8> {
        (0..len)
            .map(|index| seed.wrapping_add(u8::try_from(index % 251).unwrap()))
            .collect()
    }

    fn ingest_construct_finish_for_block_config_test(
        session: &mut ClientSession,
        manifest: &mdt_remote::RemoteManifest,
        tile_pos: i32,
        block_id: i16,
        config_object: &TypeIoObject,
    ) {
        let packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "constructFinish")
            .unwrap()
            .packet_id;
        let mut payload = Vec::new();
        payload.extend_from_slice(&tile_pos.to_be_bytes());
        payload.extend_from_slice(&block_id.to_be_bytes());
        payload.push(2);
        payload.extend_from_slice(&42i32.to_be_bytes());
        payload.push(0);
        payload.push(1);
        write_typeio_object(&mut payload, config_object);
        let packet = encode_packet(packet_id, &payload, false).unwrap();
        session.ingest_packet_bytes(&packet).unwrap();
    }

    fn ingest_deconstruct_finish_for_block_config_test(
        session: &mut ClientSession,
        manifest: &mdt_remote::RemoteManifest,
        tile_pos: i32,
        block_id: i16,
    ) {
        let packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "deconstructFinish")
            .unwrap()
            .packet_id;
        let mut payload = Vec::new();
        payload.extend_from_slice(&tile_pos.to_be_bytes());
        payload.extend_from_slice(&block_id.to_be_bytes());
        payload.push(2);
        payload.extend_from_slice(&42i32.to_be_bytes());
        let packet = encode_packet(packet_id, &payload, false).unwrap();
        session.ingest_packet_bytes(&packet).unwrap();
    }

    fn ingest_tile_config_for_block_config_test(
        session: &mut ClientSession,
        manifest: &mdt_remote::RemoteManifest,
        build_pos: i32,
        config_object: &TypeIoObject,
    ) {
        let packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "tileConfig")
            .unwrap()
            .packet_id;
        let payload = encode_tile_config_payload(Some(build_pos), config_object);
        let packet = encode_packet(packet_id, &payload, false).unwrap();
        session.ingest_packet_bytes(&packet).unwrap();
    }

    fn build_loaded_world_block_snapshot_payload(
        session: &ClientSession,
        take: usize,
    ) -> (Vec<u8>, Vec<(i32, i16, u32)>) {
        let world = &session.loaded_world_bundle().unwrap().world;
        assert!(world.building_centers.len() >= take);
        let mut data = Vec::new();
        let mut entries = Vec::new();

        for center in world.building_centers.iter().take(take) {
            let build_pos = pack_build_pos_for_block_snapshot_test(center.x, center.y);
            data.extend_from_slice(&build_pos.to_be_bytes());
            data.extend_from_slice(&(center.block_id as i16).to_be_bytes());
            data.extend_from_slice(&center.chunk_bytes[1..]);
            entries.push((
                build_pos,
                center.block_id as i16,
                center.building.base.health_bits,
            ));
        }

        let mut payload = Vec::new();
        payload.extend_from_slice(&(take as i16).to_be_bytes());
        payload.extend_from_slice(&u16::try_from(data.len()).unwrap().to_be_bytes());
        payload.extend_from_slice(&data);
        (payload, entries)
    }

    #[test]
    fn loaded_world_block_snapshot_head_fallback_uses_loaded_world_block_name_for_runtime_refresh()
    {
        let (_manifest, mut session) = loaded_world_ready_session_for_block_snapshot_test();
        let build_pos = pack_build_pos_for_block_snapshot_test(20, 21);
        let block_id = loaded_world_block_id_for_name(&session, BLOCK_NAME_MESSAGE);

        session
            .state
            .configured_block_projection
            .apply_message_text(build_pos, "loaded-world fallback".to_string());
        session.state.block_snapshot_head_projection =
            Some(crate::session_state::BlockSnapshotHeadProjection {
                build_pos,
                block_id,
                health_bits: Some(0x4000_0000),
                rotation: Some(1),
                team_id: Some(2),
                io_version: Some(3),
                enabled: Some(true),
                module_bitmask: Some(4),
                time_scale_bits: Some(0x3f80_0000),
                time_scale_duration_bits: Some(0x3f00_0000),
                last_disabler_pos: Some(123),
                legacy_consume_connected: Some(true),
                efficiency: Some(0x40),
                optional_efficiency: Some(0x20),
                visible_flags: Some(99),
            });

        session.apply_loaded_world_block_snapshot_head_fallback();

        assert_eq!(
            session
                .state()
                .building_table_projection
                .by_build_pos
                .get(&build_pos)
                .and_then(|building| building.block_name.clone()),
            Some(BLOCK_NAME_MESSAGE.to_string())
        );
        let runtime = session
            .state()
            .runtime_typed_building_apply_projection
            .building_at(build_pos)
            .expect("message runtime building should refresh from fallback");
        assert_eq!(runtime.block_id, Some(block_id));
        assert_eq!(runtime.block_name, BLOCK_NAME_MESSAGE);
        assert_eq!(
            runtime.kind,
            crate::session_state::TypedBuildingRuntimeKind::Message
        );
        assert_eq!(
            runtime.value,
            crate::session_state::TypedBuildingRuntimeValue::Text(
                "loaded-world fallback".to_string()
            )
        );
        assert_eq!(
            runtime.last_update,
            crate::session_state::BuildingProjectionUpdateKind::BlockSnapshotHead
        );
    }

    #[test]
    fn summarize_build_turret_tail_fields_extracts_rotation_presence_and_safe_count_conversion() {
        let tail = mdt_world::ParsedBuildingTail::BuildTurret(mdt_world::BuildTurretTailSnapshot {
            rotation_bits: 0x4234_0000,
            plans_present: true,
            plan_count: 2,
            plans: Vec::new(),
        });
        assert_eq!(
            summarize_build_turret_tail_fields(&tail),
            (Some(0x4234_0000), Some(true), Some(2))
        );

        let overflowing_tail =
            mdt_world::ParsedBuildingTail::BuildTurret(mdt_world::BuildTurretTailSnapshot {
                rotation_bits: 0x4270_0000,
                plans_present: true,
                plan_count: usize::from(u16::MAX).saturating_add(1),
                plans: Vec::new(),
            });
        assert_eq!(
            summarize_build_turret_tail_fields(&overflowing_tail),
            (Some(0x4270_0000), Some(true), None)
        );

        assert_eq!(
            summarize_build_turret_tail_fields(&mdt_world::ParsedBuildingTail::Empty),
            (None, None, None)
        );
    }

    #[test]
    fn summarize_building_turret_tail_fields_covers_turret_item_and_continuous_families() {
        assert_eq!(
            summarize_building_turret_tail_fields(&mdt_world::ParsedBuildingTail::Turret(
                mdt_world::TurretTailSnapshot {
                    reload_counter_bits: 0x3f80_0000,
                    rotation_bits: 0x4120_0000,
                }
            )),
            BuildingTailSummaryProjection {
                turret_reload_counter_bits: Some(0x3f80_0000),
                turret_rotation_bits: Some(0x4120_0000),
                ..BuildingTailSummaryProjection::default()
            }
        );
        assert_eq!(
            summarize_building_turret_tail_fields(&mdt_world::ParsedBuildingTail::ItemTurret(
                mdt_world::ItemTurretTailSnapshot {
                    turret: mdt_world::TurretTailSnapshot {
                        reload_counter_bits: 0x4000_0000,
                        rotation_bits: 0x4130_0000,
                    },
                    ammo_count: 7,
                    ammo: Vec::new(),
                }
            )),
            BuildingTailSummaryProjection {
                turret_reload_counter_bits: Some(0x4000_0000),
                turret_rotation_bits: Some(0x4130_0000),
                item_turret_ammo_count: Some(7),
                ..BuildingTailSummaryProjection::default()
            }
        );
        assert_eq!(
            summarize_building_turret_tail_fields(
                &mdt_world::ParsedBuildingTail::ContinuousTurret(
                    mdt_world::ContinuousTurretTailSnapshot {
                        turret: mdt_world::TurretTailSnapshot {
                            reload_counter_bits: 0x4040_0000,
                            rotation_bits: 0x4140_0000,
                        },
                        last_length_bits: 0x40c0_0000,
                    }
                )
            ),
            BuildingTailSummaryProjection {
                turret_reload_counter_bits: Some(0x4040_0000),
                turret_rotation_bits: Some(0x4140_0000),
                continuous_turret_last_length_bits: Some(0x40c0_0000),
                ..BuildingTailSummaryProjection::default()
            }
        );
    }

