    #[test]
    fn loaded_world_tail_business_helper_fail_closes_out_of_range_constructor_and_landing_pad_ids()
    {
        let (_manifest, mut session) = loaded_world_ready_session_for_block_snapshot_test();
        let constructor_pos = pack_build_pos_for_block_snapshot_test(20, 22);
        let landing_pad_pos = pack_build_pos_for_block_snapshot_test(22, 24);

        session.apply_loaded_world_parsed_tail_business(
            constructor_pos,
            Some(BLOCK_NAME_CONSTRUCTOR),
            &mdt_world::ParsedBuildingTail::Constructor(mdt_world::ConstructorTailSnapshot {
                payload_block: mdt_world::PayloadBlockTailSnapshot {
                    pay_vector_x_bits: 0,
                    pay_vector_y_bits: 0,
                    pay_rotation_bits: 0,
                    payload_present: false,
                    payload_type: None,
                    build_block_id: None,
                    build_revision: None,
                    build_payload: None,
                    unit_class_id: None,
                    unit_payload_len: None,
                    unit_payload_sha256: None,
                },
                progress_bits: 0,
                recipe_block_id: Some(0x8000),
            }),
        );
        session.apply_loaded_world_parsed_tail_business(
            landing_pad_pos,
            Some(BLOCK_NAME_LANDING_PAD),
            &mdt_world::ParsedBuildingTail::LandingPad(mdt_world::LandingPadTailSnapshot {
                config_item_id: Some(0x8000),
                priority: 0,
                cooldown_bits: 0,
                arriving_item_id: None,
                arriving_timer_bits: 0,
                liquid_removed_bits: 0,
            }),
        );

        assert!(!session
            .state()
            .configured_block_projection
            .constructor_recipe_block_by_build_pos
            .contains_key(&constructor_pos));
        assert!(!session
            .state()
            .configured_block_projection
            .landing_pad_item_by_build_pos
            .contains_key(&landing_pad_pos));
    }

    #[test]
    fn loaded_world_tail_business_helper_applies_block_name_sensitive_projection() {
        let (_manifest, mut session) = loaded_world_ready_session_for_block_snapshot_test();
        let sorter_pos = pack_build_pos_for_block_snapshot_test(52, 53);
        let duct_router_pos = pack_build_pos_for_block_snapshot_test(54, 55);
        let bridge_pos = pack_build_pos_for_block_snapshot_test(56, 57);
        let conduit_pos = pack_build_pos_for_block_snapshot_test(57, 58);
        let mass_driver_pos = pack_build_pos_for_block_snapshot_test(57, 59);
        let illuminator_pos = pack_build_pos_for_block_snapshot_test(58, 59);
        let switch_pos = pack_build_pos_for_block_snapshot_test(60, 61);
        let door_pos = pack_build_pos_for_block_snapshot_test(62, 63);
        let item_id = loaded_world_content_id_for_name(&session, ITEM_CONTENT_TYPE, "copper");

        session.apply_loaded_world_parsed_tail_business(
            sorter_pos,
            Some(BLOCK_NAME_SORTER),
            &mdt_world::ParsedBuildingTail::NullableItemRef(
                mdt_world::NullableItemRefTailSnapshot {
                    item_id: Some(item_id as u16),
                },
            ),
        );
        session.apply_loaded_world_parsed_tail_business(
            duct_router_pos,
            Some(BLOCK_NAME_DUCT_ROUTER),
            &mdt_world::ParsedBuildingTail::NullableItemRef(
                mdt_world::NullableItemRefTailSnapshot { item_id: None },
            ),
        );
        session.apply_loaded_world_parsed_tail_business(
            bridge_pos,
            Some(BLOCK_NAME_BRIDGE_CONVEYOR),
            &mdt_world::ParsedBuildingTail::ItemBridge(mdt_world::ItemBridgeTailSnapshot {
                link: 12,
                warmup_bits: 0,
                incoming: Vec::new(),
                moved: false,
            }),
        );
        session.apply_loaded_world_parsed_tail_business(
            conduit_pos,
            Some(BLOCK_NAME_PHASE_CONDUIT),
            &mdt_world::ParsedBuildingTail::ItemBridge(mdt_world::ItemBridgeTailSnapshot {
                link: 18,
                warmup_bits: 0,
                incoming: Vec::new(),
                moved: false,
            }),
        );
        session.apply_loaded_world_parsed_tail_business(
            mass_driver_pos,
            Some(BLOCK_NAME_MASS_DRIVER),
            &mdt_world::ParsedBuildingTail::MassDriver(mdt_world::MassDriverTailSnapshot {
                link: 24,
                rotation_bits: 0x41200000,
                state_ordinal: 2,
            }),
        );
        session.apply_loaded_world_parsed_tail_business(
            illuminator_pos,
            Some(BLOCK_NAME_ILLUMINATOR),
            &mdt_world::ParsedBuildingTail::OneI32(mdt_world::OneI32TailSnapshot {
                value: 0x11223344,
            }),
        );
        session.apply_loaded_world_parsed_tail_business(
            switch_pos,
            Some(BLOCK_NAME_SWITCH),
            &mdt_world::ParsedBuildingTail::OneBool(mdt_world::OneBoolTailSnapshot { value: true }),
        );
        session.apply_loaded_world_parsed_tail_business(
            door_pos,
            Some(BLOCK_NAME_DOOR_LARGE),
            &mdt_world::ParsedBuildingTail::OneBool(mdt_world::OneBoolTailSnapshot {
                value: false,
            }),
        );

        assert_eq!(
            session
                .state()
                .configured_block_projection
                .sorter_item_by_build_pos
                .get(&sorter_pos),
            Some(&Some(item_id))
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .duct_router_item_by_build_pos
                .get(&duct_router_pos),
            Some(&None)
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .item_bridge_link_by_build_pos
                .get(&bridge_pos),
            Some(&Some(12))
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .item_bridge_runtime_by_build_pos
                .get(&bridge_pos),
            Some(&ItemBridgeRuntimeProjection {
                warmup_bits: 0,
                incoming_count: 0,
                moved: false,
                buffer: None,
            })
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .item_bridge_link_by_build_pos
                .get(&conduit_pos),
            Some(&Some(18))
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .item_bridge_runtime_by_build_pos
                .get(&conduit_pos),
            Some(&ItemBridgeRuntimeProjection {
                warmup_bits: 0,
                incoming_count: 0,
                moved: false,
                buffer: None,
            })
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .mass_driver_link_by_build_pos
                .get(&mass_driver_pos),
            Some(&Some(24))
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .mass_driver_runtime_by_build_pos
                .get(&mass_driver_pos),
            Some(&MassDriverRuntimeProjection {
                rotation_bits: 0x4120_0000,
                state_ordinal: 2,
            })
        );
        assert_eq!(
            session
                .state()
                .typed_runtime_building_at(mass_driver_pos)
                .map(|building| (building.kind, building.value.clone())),
            Some((
                crate::session_state::TypedBuildingRuntimeKind::MassDriver,
                crate::session_state::TypedBuildingRuntimeValue::MassDriver {
                    link: Some(24),
                    rotation_bits: Some(0x4120_0000),
                    state_ordinal: Some(2),
                },
            ))
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .light_color_by_build_pos
                .get(&illuminator_pos),
            Some(&0x11223344)
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .switch_enabled_by_build_pos
                .get(&switch_pos),
            Some(&Some(true))
        );
        assert_eq!(
            session
                .state()
                .configured_block_projection
                .door_open_by_build_pos
                .get(&door_pos),
            Some(&Some(false))
        );
    }

