    #[test]
    fn tile_authority_packets_update_loaded_world_tiles_and_building_projection_without_mutating_baseline_centers(
    ) {
        let manifest = read_remote_manifest(real_manifest_path()).unwrap();
        let mut session = ClientSession::from_remote_manifest(&manifest, "fr").unwrap();
        ingest_sample_world(&mut session);
        let set_tile_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setTile")
            .unwrap()
            .packet_id;
        let set_tile_blocks_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setTileBlocks")
            .unwrap()
            .packet_id;
        let remove_tile_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "removeTile")
            .unwrap()
            .packet_id;

        session
            .ingest_packet_bytes(
                &encode_packet(
                    set_tile_packet_id,
                    &encode_set_tile_payload(Some(pack_point2(4, 5)), Some(29), 2, 3),
                    false,
                )
                .unwrap(),
            )
            .unwrap();
        session
            .ingest_packet_bytes(
                &encode_packet(
                    set_tile_blocks_packet_id,
                    &encode_set_tile_blocks_payload(
                        Some(11),
                        2,
                        &[pack_point2(1, 2), pack_point2(3, 4)],
                    ),
                    false,
                )
                .unwrap(),
            )
            .unwrap();

        let world = &session.loaded_world_bundle().unwrap().world;
        assert_eq!(world.tile(4, 5).unwrap().block_id, 29);
        assert_eq!(world.tile(1, 2).unwrap().block_id, 11);
        assert_eq!(world.tile(3, 4).unwrap().block_id, 11);
        let placed_building = session
            .state()
            .building_table_projection
            .by_build_pos
            .get(&pack_point2(4, 5))
            .unwrap();
        assert_eq!(placed_building.block_id, Some(29));
        assert_eq!(placed_building.team_id, Some(2));
        assert_eq!(placed_building.rotation, Some(3));
        let batch_building = session
            .state()
            .building_table_projection
            .by_build_pos
            .get(&pack_point2(1, 2))
            .unwrap();
        assert_eq!(batch_building.block_id, Some(11));
        assert_eq!(batch_building.team_id, Some(2));

        let removed_tile = world.tile(4, 4).unwrap();
        assert_ne!(removed_tile.block_id, 0);
        assert!(removed_tile.building_center_index.is_some());
        let removed_baseline_center = world.building_center_at(4, 4).unwrap();
        let removed_baseline_center_block_id = removed_baseline_center.block_id;
        session
            .ingest_packet_bytes(
                &encode_packet(
                    remove_tile_packet_id,
                    &encode_tile_payload(Some(pack_point2(4, 4))),
                    false,
                )
                .unwrap(),
            )
            .unwrap();
        let world = &session.loaded_world_bundle().unwrap().world;
        let removed_tile = world.tile(4, 4).unwrap();
        assert_eq!(removed_tile.block_id, 0);
        assert!(removed_tile.building_center_index.is_some());
        assert_eq!(
            world.building_center_at(4, 4).map(|center| center.block_id),
            Some(removed_baseline_center_block_id)
        );
        assert!(!session
            .state()
            .building_table_projection
            .by_build_pos
            .contains_key(&pack_point2(4, 4)));
    }

    #[test]
    fn team_authority_packets_update_live_projection_without_mutating_loaded_world_building_teams()
    {
        let manifest = read_remote_manifest(real_manifest_path()).unwrap();
        let mut session = ClientSession::from_remote_manifest(&manifest, "fr").unwrap();
        ingest_sample_world(&mut session);
        let set_team_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setTeam")
            .unwrap()
            .packet_id;
        let set_teams_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setTeams")
            .unwrap()
            .packet_id;
        let set_player_team_editor_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setPlayerTeamEditor")
            .unwrap()
            .packet_id;
        let build_positions = sample_build_positions_with_centers(&session, 2);
        let first_build_pos = build_positions[0];
        let second_build_pos = build_positions[1];
        let (first_x, first_y) = build_pos_to_world_xy(first_build_pos);
        let first_baseline_team = session
            .loaded_world_bundle()
            .unwrap()
            .world
            .building_center_at(first_x, first_y)
            .unwrap()
            .building
            .base
            .team_id;
        let (second_x, second_y) = build_pos_to_world_xy(second_build_pos);
        let second_baseline_team = session
            .loaded_world_bundle()
            .unwrap()
            .world
            .building_center_at(second_x, second_y)
            .unwrap()
            .building
            .base
            .team_id;

        session
            .ingest_packet_bytes(
                &encode_packet(
                    set_team_packet_id,
                    &encode_building_team_payload(Some(first_build_pos), 2),
                    false,
                )
                .unwrap(),
            )
            .unwrap();

        let first_center = session
            .loaded_world_bundle()
            .unwrap()
            .world
            .building_center_at(first_x, first_y)
            .unwrap();
        assert_eq!(first_center.building.base.team_id, first_baseline_team);
        assert_eq!(
            session
                .state()
                .building_table_projection
                .by_build_pos
                .get(&first_build_pos)
                .and_then(|building| building.team_id),
            Some(2)
        );

        session
            .ingest_packet_bytes(
                &encode_packet(
                    set_teams_packet_id,
                    &encode_set_teams_payload(3, &[first_build_pos, second_build_pos]),
                    false,
                )
                .unwrap(),
            )
            .unwrap();

        for (build_pos, baseline_team) in [
            (first_build_pos, first_baseline_team),
            (second_build_pos, second_baseline_team),
        ] {
            let (x, y) = build_pos_to_world_xy(build_pos);
            let center = session
                .loaded_world_bundle()
                .unwrap()
                .world
                .building_center_at(x, y)
                .unwrap();
            assert_eq!(center.building.base.team_id, baseline_team);
            assert_eq!(
                session
                    .state()
                    .building_table_projection
                    .by_build_pos
                    .get(&build_pos)
                    .and_then(|building| building.team_id),
                Some(3)
            );
        }

        session
            .ingest_packet_bytes(
                &encode_packet(set_player_team_editor_packet_id, &[4], false).unwrap(),
            )
            .unwrap();
        assert_eq!(session.loaded_world_bundle().unwrap().player.team_id, 4);
    }

    #[test]
    fn tile_authority_packets_project_new_tiles_without_creating_loaded_world_building_centers() {
        let manifest = read_remote_manifest(real_manifest_path()).unwrap();
        let mut session = ClientSession::from_remote_manifest(&manifest, "fr").unwrap();
        ingest_sample_world(&mut session);
        let set_tile_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setTile")
            .unwrap()
            .packet_id;
        let set_tile_blocks_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "setTileBlocks")
            .unwrap()
            .packet_id;
        let empty_positions = sample_empty_tile_positions_without_centers(&session, 2);
        let first_build_pos = empty_positions[0];
        let second_build_pos = empty_positions[1];

        session
            .ingest_packet_bytes(
                &encode_packet(
                    set_tile_packet_id,
                    &encode_set_tile_payload(Some(first_build_pos), Some(29), 2, 3),
                    false,
                )
                .unwrap(),
            )
            .unwrap();
        session
            .ingest_packet_bytes(
                &encode_packet(
                    set_tile_blocks_packet_id,
                    &encode_set_tile_blocks_payload(Some(11), 4, &[second_build_pos]),
                    false,
                )
                .unwrap(),
            )
            .unwrap();

        let world = &session.loaded_world_bundle().unwrap().world;
        let (first_x, first_y) = build_pos_to_world_xy(first_build_pos);
        let first_tile = world.tile(first_x, first_y).unwrap();
        assert_eq!(first_tile.block_id, 29);
        assert!(first_tile.building_center_index.is_none());
        assert!(world.building_center_at(first_x, first_y).is_none());
        let first_building = session
            .state()
            .building_table_projection
            .by_build_pos
            .get(&first_build_pos)
            .unwrap();
        assert_eq!(first_building.block_id, Some(29));
        assert_eq!(first_building.team_id, Some(2));
        assert_eq!(first_building.rotation, Some(3));

        let (second_x, second_y) = build_pos_to_world_xy(second_build_pos);
        let second_tile = world.tile(second_x, second_y).unwrap();
        assert_eq!(second_tile.block_id, 11);
        assert!(second_tile.building_center_index.is_none());
        assert!(world.building_center_at(second_x, second_y).is_none());
        let second_building = session
            .state()
            .building_table_projection
            .by_build_pos
            .get(&second_build_pos)
            .unwrap();
        assert_eq!(second_building.block_id, Some(11));
        assert_eq!(second_building.team_id, Some(4));
        assert_eq!(second_building.rotation, None);
    }

    #[test]
    fn construct_deconstruct_and_build_health_packets_update_live_projection_without_patching_loaded_world_centers(
    ) {
        let manifest = read_remote_manifest(real_manifest_path()).unwrap();
        let mut session = ClientSession::from_remote_manifest(&manifest, "fr").unwrap();
        ingest_sample_world(&mut session);
        let empty_build_pos = sample_empty_tile_positions_without_centers(&session, 1)[0];
        let block_id = loaded_world_block_id_for_name(&session, "router");
        let build_health_update_packet_id = manifest
            .remote_packets
            .iter()
            .find(|entry| entry.method == "buildHealthUpdate")
            .unwrap()
            .packet_id;

        ingest_construct_finish_for_block_config_test(
            &mut session,
            &manifest,
            empty_build_pos,
            block_id,
            &TypeIoObject::Null,
        );

        let (x, y) = build_pos_to_world_xy(empty_build_pos);
        let world = &session.loaded_world_bundle().unwrap().world;
        let placed_tile = world.tile(x, y).unwrap();
        assert_eq!(placed_tile.block_id, u16::try_from(block_id).unwrap());
        assert!(placed_tile.building_center_index.is_none());
        assert!(world.building_center_at(x, y).is_none());
        let placed_building = session
            .state()
            .building_table_projection
            .by_build_pos
            .get(&empty_build_pos)
            .unwrap();
        assert_eq!(placed_building.block_id, Some(block_id));
        assert_eq!(placed_building.team_id, Some(1));
        assert_eq!(placed_building.rotation, Some(0));

        let mut build_health_payload = Vec::new();
        build_health_payload.extend_from_slice(&2i32.to_be_bytes());
        build_health_payload.extend_from_slice(&empty_build_pos.to_be_bytes());
        build_health_payload.extend_from_slice(&(1.5f32.to_bits() as i32).to_be_bytes());
        session
            .ingest_packet_bytes(
                &encode_packet(build_health_update_packet_id, &build_health_payload, false)
                    .unwrap(),
            )
            .unwrap();
        let world = &session.loaded_world_bundle().unwrap().world;
        assert!(world.building_center_at(x, y).is_none());
        assert_eq!(
            session
                .state()
                .building_table_projection
                .by_build_pos
                .get(&empty_build_pos)
                .and_then(|building| building.health_bits),
            Some(1.5f32.to_bits())
        );

        ingest_deconstruct_finish_for_block_config_test(
            &mut session,
            &manifest,
            empty_build_pos,
            block_id,
        );
        let world = &session.loaded_world_bundle().unwrap().world;
        let removed_tile = world.tile(x, y).unwrap();
        assert_eq!(removed_tile.block_id, 0);
        assert!(removed_tile.building_center_index.is_none());
        assert!(world.building_center_at(x, y).is_none());
    }

    #[test]
    fn building_live_state_prefers_projection_fields_over_loaded_world_baseline() {
        let manifest = read_remote_manifest(real_manifest_path()).unwrap();
        let mut session = ClientSession::from_remote_manifest(&manifest, "fr").unwrap();
        ingest_sample_world(&mut session);
        let build_pos = sample_build_positions_with_centers(&session, 1)[0];
        let baseline = session.building_live_state_at(build_pos).unwrap();
        let mut replacement_block_id = loaded_world_block_id_for_name(&session, BLOCK_NAME_MESSAGE);
        if baseline.projection.block_id == Some(replacement_block_id) {
            replacement_block_id = loaded_world_block_id_for_name(&session, "router");
        }

        session
            .state
            .building_table_projection
            .apply_remote_tile_authority(
                build_pos,
                replacement_block_id,
                session.loaded_world_block_name(replacement_block_id),
                Some(3),
                Some(4),
            );

        let live = session.building_live_state_at(build_pos).unwrap();
        assert_eq!(live.projection.block_id, Some(replacement_block_id));
        assert_eq!(
            live.projection.block_name,
            session.loaded_world_block_name(replacement_block_id)
        );
        assert_eq!(live.projection.rotation, Some(3));
        assert_eq!(live.projection.team_id, Some(4));
    }

